=\\\\\\\\\\\\\\\"#demo-placeholder\\\\\\\\\\\\\\\" class=\\\\\\\\\\\\\\\"btn btn--outline\\\\\\\\\\\\\\\">Learn More</a>\\\\\\\\n        </div>\\\\\\\\n      </div>\\\\\\\\n    </div>\\\\\\\\n  </section>\\\\\\\\n\\\\\\\\n  <!-- ======== FINAL CTA ======== -->\\\\\\\\n  <section class=\\\\\\\\\\\\\\\"section section--indigo final-cta\\\\\\\\\\\\\\\">\\\\\\\\n    <div class=\\\\\\\\\\\\\\\"container\\\\\\\\\\\\\\\">\\\\\\\\n      <h2 class=\\\\\\\\\\\\\\\"t-display t-display--lg\\\\\\\\\\\\\\\">Give your congregation the home they deserve.</h2>\\\\\\\\n      <p class=\\\\\\\\\\\\\\\"t-body--lg\\\\\\\\\\\\\\\">Open source. Flat pricing. AI-powered. Yours forever.</p>\\\\\\\\n      <div class=\\\\\\\\\\\\\\\"final-cta__buttons\\\\\\\\\\\\\\\">\\\\\\\\n        <a href=\\\\\\\\\\\\\\\"#demo-placeholder\\\\\\\\\\\\\\\" class=\\\\\\\\\\\\\\\"btn btn--white btn--lg\\\\\\\\\\\\\\\">Build Your Church Portal &rarr;</a>\\\\\\\\n        <a href=\\\\\\\\\\\\\\\"https://github.com/kychee-com/wildlychee\\\\\\\\\\\\\\\" class=\\\\\\\\\\\\\\\"btn btn--outline btn--lg\\\\\\\\\\\\\\\" style=\\\\\\\\\\\\\\\"border-color:#fff;color:#fff\\\\\\\\\\\\\\\" target=\\\\\\\\\\\\\\\"_blank\\\\\\\\\\\\\\\">Fork on GitHub</a>\\\\\\\\n      </div>\\\\\\\\n    </div>\\\\\\\\n  </section>\\\\\\\\n\\\\\\\\n  <!-- ======== FOOTER ======== -->\\\\\\\\n  <footer class=\\\\\\\\\\\\\\\"footer\\\\\\\\\\\\\\\">\\\\\\\\n    <div class=\\\\\\\\\\\\\\\"container\\\\\\\\\\\\\\\">\\\\\\\\n      <p>\\\\\\\\n        <strong>Wild Lychee</strong> is open source. Built on <a href=\\\\\\\\\\\\\\\"https://run402.com\\\\\\\\\\\\\\\" target=\\\\\\\\\\\\\\\"_blank\\\\\\\\\\\\\\\">Run402</a>.\\\\\\\\n        &ensp;&middot;&ensp;\\\\\\\\n        <a href=\\\\\\\\\\\\\\\"https://github.com/kychee-com/wildlychee\\\\\\\\\\\\\\\" target=\\\\\\\\\\\\\\\"_blank\\\\\\\\\\\\\\\">GitHub</a>\\\\\\\\n        &ensp;&middot;&ensp;\\\\\\\\n        <a href=\\\\\\\\\\\\\\\"https://eagles.run402.com\\\\\\\\\\\\\\\" target=\\\\\\\\\\\\\\\"_blank\\\\\\\\\\\\\\\">Eagles Demo</a>\\\\\\\\n      </p>\\\\\\\\n    </div>\\\\\\\\n  </footer>\\\\\\\\n\\\\\\\\n  <!-- Mobile nav toggle -->\\\\\\\\n  <script>\\\\\\\\n    document.getElementById('nav-toggle')?.addEventListener('click', () => {\\\\\\\\n      document.getElementById('nav-links')?.classList.toggle('open');\\\\\\\\n    });\\\\\\\\n  </script>\\\\\\\\n\\\\\\\\n</body>\\\\\\\\n</html>\\\\\\\\n\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"file\\\\\\\": \\\\\\\"css/marketing.css\\\\\\\",\\\\n      \\\\\\\"data\\\\\\\": \\\\\\\"/* ============================================\\\\\\\\n   Wild Lychee Marketing вҖ” Editorial Indie\\\\\\\\n   ============================================ */\\\\\\\\n\\\\\\\\n@import url('https://fonts.googleapis.com/css2?family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;0,9..40,700;1,9..40,400&family=Instrument+Serif:ital@0;1&display=swap');\\\\\\\\n\\\\\\\\n/* --- Tokens --- */\\\\\\\\n:root {\\\\\\\\n  --ink: #1a1625;\\\\\\\\n  --ink-muted: #6b6680;\\\\\\\\n  --ink-subtle: #9994a8;\\\\\\\\n  --cream: #faf7f2;\\\\\\\\n  --cream-dark: #f0ebe3;\\\\\\\\n  --indigo: #4338ca;\\\\\\\\n  --indigo-light: #6366f1;\\\\\\\\n  --indigo-dark: #3730a3;\\\\\\\\n  --indigo-wash: #eef2ff;\\\\\\\\n  --coral: #f97316;\\\\\\\\n  --coral-light: #fb923c;\\\\\\\\n  --green: #16a34a;\\\\\\\\n  --green-wash: #dcfce7;\\\\\\\\n  --red-wash: #fee2e2;\\\\\\\\n  --red-muted: #b91c1c;\\\\\\\\n  --font-display: 'Instrument Serif', Georgia, serif;\\\\\\\\n  --font-body: 'DM Sans', -apple-system, sans-serif;\\\\\\\\n  --max-w: 72rem;\\\\\\\\n  --ease: cubic-bezier(0.16, 1, 0.3, 1);\\\\\\\\n}\\\\\\\\n\\\\\\\\n/* --- Reset --- */\\\\\\\\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\\\\\\\\n\\\\\\\\nhtml { scroll-behavior: smooth; }\\\\\\\\n\\\\\\\\nbody {\\\\\\\\n  font-family: var(--font-body);\\\\\\\\n  color: var(--ink);\\\\\\\\n  background: var(--cream);\\\\\\\\n  line-height: 1.65;\\\\\\\\n  -webkit-font-smoothing: antialiased;\\\\\\\\n  overflow-x: hidden;\\\\\\\\n}\\\\\\\\n\\\\\\\\nimg { max-width: 100%; display: block; }\\\\\\\\na { color: inherit; text-decoration: none; }\\\\\\\\n\\\\\\\\n/* --- Layout --- */\\\\\\\\n.container {\\\\\\\\n  max-width: var(--max-w);\\\\\\\\n  margin: 0 auto;\\\\\\\\n  padding: 0 2rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.section {\\\\\\\\n  padding: 7rem 0;\\\\\\\\n  position: relative;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.section--cream { background: var(--cream); }\\\\\\\\n.section--white { background: #fff; }\\\\\\\\n.section--ink {\\\\\\\\n  background: var(--ink);\\\\\\\\n  color: #fff;\\\\\\\\n}\\\\\\\\n.section--indigo {\\\\\\\\n  background: var(--indigo);\\\\\\\\n  color: #fff;\\\\\\\\n}\\\\\\\\n\\\\\\\\n/* Dot-grid texture overlay */\\\\\\\\n.section--dotted::before {\\\\\\\\n  content: '';\\\\\\\\n  position: absolute;\\\\\\\\n  inset: 0;\\\\\\\\n  background-image: radial-gradient(circle, var(--ink) 0.5px, transparent 0.5px);\\\\\\\\n  background-size: 24px 24px;\\\\\\\\n  opacity: 0.04;\\\\\\\\n  pointer-events: none;\\\\\\\\n}\\\\\\\\n\\\\\\\\n/* Angled divider */\\\\\\\\n.slash {\\\\\\\\n  position: relative;\\\\\\\\n}\\\\\\\\n.slash::after {\\\\\\\\n  content: '';\\\\\\\\n  position: absolute;\\\\\\\\n  bottom: -2rem;\\\\\\\\n  left: 0;\\\\\\\\n  right: 0;\\\\\\\\n  height: 4rem;\\\\\\\\n  background: inherit;\\\\\\\\n  clip-path: polygon(0 0, 100% 0, 100% 30%, 0 100%);\\\\\\\\n  z-index: 2;\\\\\\\\n}\\\\\\\\n\\\\\\\\n/* --- Typography --- */\\\\\\\\n.t-display {\\\\\\\\n  font-family: var(--font-display);\\\\\\\\n  font-weight: 400;\\\\\\\\n  line-height: 1.1;\\\\\\\\n  letter-spacing: -0.02em;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.t-display--xl { font-size: clamp(2.75rem, 6vw, 4.5rem); }\\\\\\\\n.t-display--lg { font-size: clamp(2rem, 4vw, 3rem); }\\\\\\\\n.t-display--md { font-size: clamp(1.5rem, 3vw, 2.25rem); }\\\\\\\\n\\\\\\\\n.t-overline {\\\\\\\\n  font-family: var(--font-body);\\\\\\\\n  font-size: 0.8125rem;\\\\\\\\n  font-weight: 600;\\\\\\\\n  letter-spacing: 0.1em;\\\\\\\\n  text-transform: uppercase;\\\\\\\\n  color: var(--indigo);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.t-body { font-size: 1.125rem; color: var(--ink-muted); }\\\\\\\\n.t-body--lg { font-size: 1.25rem; color: var(--ink-muted); max-width: 38rem; }\\\\\\\\n.t-body--sm { font-size: 0.9375rem; color: var(--ink-muted); }\\\\\\\\n\\\\\\\\n.t-italic { font-style: italic; }\\\\\\\\n\\\\\\\\n/* --- Nav --- */\\\\\\\\n.nav {\\\\\\\\n  position: sticky;\\\\\\\\n  top: 0;\\\\\\\\n  z-index: 100;\\\\\\\\n  background: rgba(250, 247, 242, 0.9);\\\\\\\\n  backdrop-filter: blur(12px);\\\\\\\\n  -webkit-backdrop-filter: blur(12px);\\\\\\\\n  border-bottom: 1px solid rgba(26, 22, 37, 0.06);\\\\\\\\n  padding: 0.875rem 0;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.nav__inner {\\\\\\\\n  display: flex;\\\\\\\\n  align-items: center;\\\\\\\\n  gap: 2rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.nav__brand {\\\\\\\\n  font-family: var(--font-display);\\\\\\\\n  font-size: 1.375rem;\\\\\\\\n  color: var(--ink);\\\\\\\\n  display: flex;\\\\\\\\n  align-items: center;\\\\\\\\n  gap: 0.5rem;\\\\\\\\n  flex-shrink: 0;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.nav__brand-icon {\\\\\\\\n  width: 1.75rem;\\\\\\\\n  height: 1.75rem;\\\\\\\\n  background: var(--indigo);\\\\\\\\n  border-radius: 6px;\\\\\\\\n  display: flex;\\\\\\\\n  align-items: center;\\\\\\\\n  justify-content: center;\\\\\\\\n  color: #fff;\\\\\\\\n  font-size: 1rem;\\\\\\\\n  transform: rotate(-6deg);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.nav__links {\\\\\\\\n  display: flex;\\\\\\\\n  align-items: center;\\\\\\\\n  gap: 0.25rem;\\\\\\\\n  margin-left: auto;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.nav__link {\\\\\\\\n  padding: 0.375rem 0.75rem;\\\\\\\\n  font-size: 0.875rem;\\\\\\\\n  font-weight: 500;\\\\\\\\n  color: var(--ink-muted);\\\\\\\\n  border-radius: 6px;\\\\\\\\n  transition: color 0.2s, background 0.2s;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.nav__link:hover {\\\\\\\\n  color: var(--ink);\\\\\\\\n  background: rgba(0,0,0,0.04);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.nav__cta {\\\\\\\\n  margin-left: 0.5rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.nav__toggle {\\\\\\\\n  display: none;\\\\\\\\n  background: none;\\\\\\\\n  border: none;\\\\\\\\n  font-size: 1.5rem;\\\\\\\\n  cursor: pointer;\\\\\\\\n  color: var(--ink);\\\\\\\\n  padding: 0.25rem;\\\\\\\\n  margin-left: auto;\\\\\\\\n}\\\\\\\\n\\\\\\\\n/* --- Buttons --- */\\\\\\\\n.btn {\\\\\\\\n  display: inline-flex;\\\\\\\\n  align-items: center;\\\\\\\\n  gap: 0.5rem;\\\\\\\\n  padding: 0.75rem 1.5rem;\\\\\\\\n  border-radius: 8px;\\\\\\\\n  font-family: var(--font-body);\\\\\\\\n  font-size: 0.9375rem;\\\\\\\\n  font-weight: 600;\\\\\\\\n  border: none;\\\\\\\\n  cursor: pointer;\\\\\\\\n  transition: transform 0.15s var(--ease), box-shadow 0.2s, background 0.2s;\\\\\\\\n  text-decoration: none;\\\\\\\\n}\\\\\\\\n.btn:active { transform: scale(0.97); }\\\\\\\\n\\\\\\\\n.btn--primary {\\\\\\\\n  background: var(--indigo);\\\\\\\\n  color: #fff;\\\\\\\\n  box-shadow: 0 1px 3px rgba(67, 56, 202, 0.3);\\\\\\\\n}\\\\\\\\n.btn--primary:hover {\\\\\\\\n  background: var(--indigo-dark);\\\\\\\\n  box-shadow: 0 4px 12px rgba(67, 56, 202, 0.3);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.btn--outline {\\\\\\\\n  background: transparent;\\\\\\\\n  color: var(--ink);\\\\\\\\n  border: 1.5px solid var(--ink);\\\\\\\\n}\\\\\\\\n.btn--outline:hover {\\\\\\\\n  background: var(--ink);\\\\\\\\n  color: var(--cream);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.btn--ghost {\\\\\\\\n  background: transparent;\\\\\\\\n  color: var(--indigo);\\\\\\\\n  padding: 0.75rem 1rem;\\\\\\\\n}\\\\\\\\n.btn--ghost:hover {\\\\\\\\n  background: var(--indigo-wash);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.btn--coral {\\\\\\\\n  background: var(--coral);\\\\\\\\n  color: #fff;\\\\\\\\n}\\\\\\\\n.btn--coral:hover {\\\\\\\\n  background: var(--coral-light);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.btn--white {\\\\\\\\n  background: #fff;\\\\\\\\n  color: var(--indigo);\\\\\\\\n}\\\\\\\\n.btn--white:hover {\\\\\\\\n  background: var(--cream);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.btn--lg {\\\\\\\\n  padding: 1rem 2rem;\\\\\\\\n  font-size: 1.0625rem;\\\\\\\\n  border-radius: 10px;\\\\\\\\n}\\\\\\\\n\\\\\\\\n/* --- Hero --- */\\\\\\\\n.hero {\\\\\\\\n  padding: 8rem 0 6rem;\\\\\\\\n  position: relative;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.hero__content {\\\\\\\\n  max-width: 48rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.hero__headline {\\\\\\\\n  margin-bottom: 1.5rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.hero__headline em {\\\\\\\\n  color: var(--coral);\\\\\\\\n  font-style: normal;\\\\\\\\n  text-decoration: underline;\\\\\\\\n  text-decoration-color: var(--coral);\\\\\\\\n  text-underline-offset: 4px;\\\\\\\\n  text-decoration-thickness: 3px;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.hero__sub {\\\\\\\\n  margin-bottom: 2.5rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.hero__ctas {\\\\\\\\n  display: flex;\\\\\\\\n  flex-wrap: wrap;\\\\\\\\n  gap: 0.75rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.hero__aside {\\\\\\\\n  position: absolute;\\\\\\\\n  right: 2rem;\\\\\\\\n  top: 50%;\\\\\\\\n  transform: translateY(-50%);\\\\\\\\n  width: 20rem;\\\\\\\\n  height: 20rem;\\\\\\\\n  background: var(--indigo-wash);\\\\\\\\n  border-radius: 50%;\\\\\\\\n  opacity: 0.5;\\\\\\\\n  filter: blur(60px);\\\\\\\\n  pointer-events: none;\\\\\\\\n}\\\\\\\\n\\\\\\\\n/* --- Problem cards --- */\\\\\\\\n.problem-grid {\\\\\\\\n  display: grid;\\\\\\\\n  grid-template-columns: repeat(3, 1fr);\\\\\\\\n  gap: 1.5rem;\\\\\\\\n  margin-bottom: 4rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.problem-card {\\\\\\\\n  background: #fff;\\\\\\\\n  border: 1px solid rgba(0,0,0,0.06);\\\\\\\\n  border-radius: 12px;\\\\\\\\n  padding: 2rem;\\\\\\\\n  position: relative;\\\\\\\\n  overflow: hidden;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.problem-card::before {\\\\\\\\n  content: '';\\\\\\\\n  position: absolute;\\\\\\\\n  top: 0;\\\\\\\\n  left: 0;\\\\\\\\n  right: 0;\\\\\\\\n  height: 3px;\\\\\\\\n  background: var(--red-muted);\\\\\\\\n  opacity: 0.6;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.problem-card__name {\\\\\\\\n  font-weight: 700;\\\\\\\\n  font-size: 0.875rem;\\\\\\\\n  color: var(--red-muted);\\\\\\\\n  text-transform: uppercase;\\\\\\\\n  letter-spacing: 0.05em;\\\\\\\\n  margin-bottom: 0.75rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.problem-card__price {\\\\\\\\n  font-family: var(--font-display);\\\\\\\\n  font-size: 1.75rem;\\\\\\\\n  line-height: 1.2;\\\\\\\\n  margin-bottom: 0.5rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.problem-card__desc {\\\\\\\\n  font-size: 0.9375rem;\\\\\\\\n  color: var(--ink-muted);\\\\\\\\n  font-style: italic;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.problem-transition {\\\\\\\\n  text-align: center;\\\\\\\\n  max-width: 36rem;\\\\\\\\n  margin: 0 auto;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.problem-transition__what-if {\\\\\\\\n  font-family: var(--font-display);\\\\\\\\n  font-size: 2rem;\\\\\\\\n  font-style: italic;\\\\\\\\n  color: var(--indigo);\\\\\\\\n  margin-bottom: 1rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n/* --- Feature grid --- */\\\\\\\\n.feature-grid {\\\\\\\\n  display: grid;\\\\\\\\n  grid-template-columns: repeat(4, 1fr);\\\\\\\\n  gap: 1.25rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.feature-card {\\\\\\\\n  background: #fff;\\\\\\\\n  border: 1px solid rgba(0,0,0,0.06);\\\\\\\\n  border-radius: 12px;\\\\\\\\n  padding: 1.75rem;\\\\\\\\n  transition: transform 0.2s var(--ease), box-shadow 0.2s;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.feature-card:hover {\\\\\\\\n  transform: translateY(-2px);\\\\\\\\n  box-shadow: 0 8px 24px rgba(0,0,0,0.06);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.feature-card__icon {\\\\\\\\n  font-size: 1.75rem;\\\\\\\\n  margin-bottom: 0.75rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.feature-card__name {\\\\\\\\n  font-weight: 700;\\\\\\\\n  font-size: 1rem;\\\\\\\\n  margin-bottom: 0.375rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.feature-card__desc {\\\\\\\\n  font-size: 0.875rem;\\\\\\\\n  color: var(--ink-muted);\\\\\\\\n  line-height: 1.5;\\\\\\\\n}\\\\\\\\n\\\\\\\\n/* --- AI section --- */\\\\\\\\n.ai-section {\\\\\\\\n  background: var(--ink);\\\\\\\\n  color: #fff;\\\\\\\\n  position: relative;\\\\\\\\n  overflow: hidden;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.ai-section .t-overline { color: var(--coral-light); }\\\\\\\\n.ai-section .t-body--lg { color: rgba(255,255,255,0.6); }\\\\\\\\n\\\\\\\\n.ai-grid {\\\\\\\\n  display: grid;\\\\\\\\n  grid-template-columns: repeat(3, 1fr);\\\\\\\\n  gap: 1.25rem;\\\\\\\\n  margin-bottom: 2rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.ai-card {\\\\\\\\n  background: rgba(255,255,255,0.06);\\\\\\\\n  border: 1px solid rgba(255,255,255,0.08);\\\\\\\\n  border-radius: 12px;\\\\\\\\n  padding: 1.75rem;\\\\\\\\n  transition: background 0.2s;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.ai-card:hover {\\\\\\\\n  background: rgba(255,255,255,0.1);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.ai-card__icon {\\\\\\\\n  font-size: 1.5rem;\\\\\\\\n  margin-bottom: 0.75rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.ai-card__name {\\\\\\\\n  font-weight: 700;\\\\\\\\n  font-size: 1rem;\\\\\\\\n  margin-bottom: 0.375rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.ai-card__desc {\\\\\\\\n  font-size: 0.875rem;\\\\\\\\n  color: rgba(255,255,255,0.55);\\\\\\\\n  line-height: 1.5;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.ai-byok {\\\\\\\\n  display: inline-flex;\\\\\\\\n  align-items: center;\\\\\\\\n  gap: 0.5rem;\\\\\\\\n  background: rgba(255,255,255,0.06);\\\\\\\\n  border: 1px solid rgba(255,255,255,0.1);\\\\\\\\n  border-radius: 8px;\\\\\\\\n  padding: 0.75rem 1.25rem;\\\\\\\\n  font-size: 0.875rem;\\\\\\\\n  color: rgba(255,255,255,0.7);\\\\\\\\n}\\\\\\\\n\\\\\\\\n/* Background glow */\\\\\\\\n.ai-section::before {\\\\\\\\n  content: '';\\\\\\\\n  position: absolute;\\\\\\\\n  top: -10rem;\\\\\\\\n  right: -10rem;\\\\\\\\n  width: 30rem;\\\\\\\\n  height: 30rem;\\\\\\\\n  background: radial-gradient(circle, var(--indigo) 0%, transparent 70%);\\\\\\\\n  opacity: 0.15;\\\\\\\\n  pointer-events: none;\\\\\\\\n}\\\\\\\\n\\\\\\\\n/* --- Showcase gallery --- */\\\\\\\\n.showcase-grid {\\\\\\\\n  display: grid;\\\\\\\\n  grid-template-columns: repeat(3, 1fr);\\\\\\\\n  gap: 1.5rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.showcase-card {\\\\\\\\n  border-radius: 12px;\\\\\\\\n  overflow: hidden;\\\\\\\\n  border: 1px solid rgba(0,0,0,0.08);\\\\\\\\n  background: #fff;\\\\\\\\n  transition: transform 0.2s var(--ease), box-shadow 0.2s;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.showcase-card:hover {\\\\\\\\n  transform: translateY(-3px);\\\\\\\\n  box-shadow: 0 12px 32px rgba(0,0,0,0.08);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.showcase-card__preview {\\\\\\\\n  height: 12rem;\\\\\\\\n  display: flex;\\\\\\\\n  align-items: center;\\\\\\\\n  justify-content: center;\\\\\\\\n  font-family: var(--font-display);\\\\\\\\n  font-size: 1.25rem;\\\\\\\\n  color: #fff;\\\\\\\\n  position: relative;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.showcase-card__preview--eagles {\\\\\\\\n  background: linear-gradient(135deg, #1b365d 0%, #2d4a7a 100%);\\\\\\\\n}\\\\\\\\n.showcase-card__preview--yoga {\\\\\\\\n  background: linear-gradient(135deg, #7c3aed 0%, #a78bfa 100%);\\\\\\\\n}\\\\\\\\n.showcase-card__preview--bookclub {\\\\\\\\n  background: linear-gradient(135deg, #065f46 0%, #059669 100%);\\\\\\\\n}\\\\\\\\n\\\\\\\\n.showcase-card__coming {\\\\\\\\n  position: absolute;\\\\\\\\n  top: 0.75rem;\\\\\\\\n  right: 0.75rem;\\\\\\\\n  background: rgba(0,0,0,0.5);\\\\\\\\n  color: #fff;\\\\\\\\n  font-family: var(--font-body);\\\\\\\\n  font-size: 0.6875rem;\\\\\\\\n  font-weight: 600;\\\\\\\\n  padding: 0.25rem 0.625rem;\\\\\\\\n  border-radius: 99px;\\\\\\\\n  text-transform: uppercase;\\\\\\\\n  letter-spacing: 0.05em;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.showcase-card__body {\\\\\\\\n  padding: 1.25rem 1.5rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.showcase-card__name {\\\\\\\\n  font-weight: 700;\\\\\\\\n  font-size: 1.0625rem;\\\\\\\\n  margin-bottom: 0.25rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.showcase-card__niche {\\\\\\\\n  font-size: 0.8125rem;\\\\\\\\n  color: var(--ink-muted);\\\\\\\\n  margin-bottom: 0.75rem;\\\\\\\\n}\\\\\\\\n\\\\\\\\n.showcase-card__link {\\\\\\\\n  font-size: 0.875rem;\\\\\\\\n  font-weight: 600;\\\\\\\\n  color: var(--indigo);\\\\\\\\n  display: inline-flex;\\\\\\\\n  align-items: center;\\\\\\\\n  gap: 0.25rem;\\\\\\\\n}\\\\\\