temp /tmp/capture-XXXXXX.html)\\\\n  cat > \\\\\\\"$tmphtml\\\\\\\" <<HTMLEOF\\\\n<!DOCTYPE html>\\\\n<html><body><script>\\\\n  // Navigate and wait for content to load\\\\n  window.location = '$url';\\\\n</script></body></html>\\\\nHTMLEOF\\\\n\\\\n  # Use virtual-time-budget to let JS execute (5 seconds of simulated time)\\\\n  \\\\\\\"$CHROME\\\\\\\" \\\\\\\\\\\\n    --headless=new \\\\\\\\\\\\n    --disable-gpu \\\\\\\\\\\\n    --no-sandbox \\\\\\\\\\\\n    --hide-scrollbars \\\\\\\\\\\\n    --window-size=\\\\\\\"${WIDTH},${HEIGHT}\\\\\\\" \\\\\\\\\\\\n    --virtual-time-budget=8000 \\\\\\\\\\\\n    --screenshot=\\\\\\\"$output\\\\\\\" \\\\\\\\\\\\n    \\\\\\\"$url\\\\\\\" \\\\\\\\\\\\n    2>/dev/null\\\\n\\\\n  rm -f \\\\\\\"$tmphtml\\\\\\\"\\\\n\\\\n  if [[ -f \\\\\\\"$output\\\\\\\" ]]; then\\\\n    local size=$(du -h \\\\\\\"$output\\\\\\\" | cut -f1)\\\\n    echo \\\\\\\"  Saved: $output ($size)\\\\\\\"\\\\n  else\\\\n    echo \\\\\\\"  FAILED: $output not created\\\\\\\"\\\\n  fi\\\\n}\\\\n\\\\n# Showcase sites вҖ” add more as they're created\\\\ntypeset -A SITES\\\\nSITES=(\\\\n  eagles \\\\\\\"https://eagles.run402.com\\\\\\\"\\\\n  # yoga   \\\\\\\"https://yoga.run402.com\\\\\\\"\\\\n  # bookclub \\\\\\\"https://bookclub.run402.com\\\\\\\"\\\\n)\\\\n\\\\nif [[ -n \\\\\\\"$1\\\\\\\" ]]; then\\\\n  if [[ -n \\\\\\\"${SITES[$1]}\\\\\\\" ]]; then\\\\n    capture \\\\\\\"$1\\\\\\\" \\\\\\\"${SITES[$1]}\\\\\\\"\\\\n  else\\\\n    echo \\\\\\\"Unknown site: $1\\\\\\\"\\\\n    echo \\\\\\\"Available: ${(k)SITES}\\\\\\\"\\\\n    exit 1\\\\n  fi\\\\nelse\\\\n  for name url in \\\\\\\"${(@kv)SITES}\\\\\\\"; do\\\\n    capture \\\\\\\"$name\\\\\\\" \\\\\\\"$url\\\\\\\"\\\\n  done\\\\nfi\\\\n\\\\necho \\\\\\\"Done.\\\\\\\"\\\\n\\\"\\n    },\\n    {\\n      \\\"file\\\": \\\"churches.html\\\",\\n      \\\"data\\\": \\\"<!DOCTYPE html>\\\\n<html lang=\\\\\\\"en\\\\\\\">\\\\n<head>\\\\n  <meta charset=\\\\\\\"UTF-8\\\\\\\">\\\\n  <meta name=\\\\\\\"viewport\\\\\\\" co