class=\\\\\\\"hero__aside\\\\\\\" aria-hidden=\\\\\\\"true\\\\\\\"></div>\\\\n  </section>\\\\n\\\\n  <!-- ======== FEATURES ======== -->\\\\n  <section class=\\\\\\\"section section--white\\\\\\\" id=\\\\\\\"features\\\\\\\">\\\\n    <div class=\\\\\\\"container\\\\\\\">\\\\n      <div class=\\\\\\\"section-header\\\\\\\">\\\\n        <p class=\\\\\\\"t-overline\\\\\\\">Built for HOAs</p>\\\\n        <h2 class=\\\\\\\"t-display t-display--lg\\\\\\\">Everything your community association needs.</h2>\\\\n        <p class=\\\\\\\"t-body--lg mt-2\\\\\\\">Six HOA-specific features, ready out of the box. Toggle them on with a config flag.</p>\\\\n      </div>\\\\n\\\\n      <div class=\\\\\\\"feature-grid\\\\\\\">\\\\n        <div class=\\\\\\\"feature-card\\\\\\\">\\\\n          <div class=\\\\\\\"feature-card__icon\\\\\\\">&#128295;</div>\\\\n          <div class=\\\\\\\"feature-card__name\\\\\\\">Maintenance Requests</div>\\\\n          <div class=\\\\\\\"feature-card__desc\\\\\\\">Residents submit issues with photos and descriptions. Board tracks status from open to resolved.</div>\\\\n        </div>\\\\n        <div class=\\\\\\\"feature-card\\\\\\\">\\\\n          <div class=\\\\\\\"feature-card__icon\\\\\\\">&#128196;</div>\\\\n          <div class=\\\\\\\"feature-card__name\\\\\\\">Document Archive</div>\\\\n          <div class=\\\\\\\"feature-card__desc\\\\\\\">CC&amp;Rs, meeting minutes, financial reports, and bylaws &mdash; organized, searchable, and always accessible.</div>\\\\n        </div>\\\\n        <div class=\\\\\\\"feature-card\\\\\\\">\\\\n          <div class=\\\\\\\"feature-card__icon\\\\\\\">&#9989;</div>\\\\n          <div class=\\\\\\\"feature-card__name\\\\\\\">Voting &amp; Polls</div>\\\\n          <div class=\\\\\\\"feature-card__desc\\\\\\\">Run board elections, budget approvals, and community polls with transparent results and audit trails.</div>\\\\n        </div>\\\\n        <div class=\\\\\\\"feature-card\\\\\\\">\\\\n          <div class=\\\\\\\"feature-card__icon\\\\\\\">&#128100;</div>\\\\n          <div class=\\\\\\\"feature-card__name\\\\\\\">Resident &amp; Board Roles</div>\\\\n          <div class=\\\\\\\"feature-card__desc\\\\\\\">Separate permissions for residents, board members, and property managers. Everyone sees what they need.</div>\\\\n        </div>\\\\n        <div class=\\\\\\\"feature-card\\\\\\\">\\\\n          <div class=\\\\\\\"feature-card__icon\\\\\\\">&#128247;</div>\\\\n          <div class=\\\\\\\"feature-card__name\\\\\\\">Issue Submission</div>\\\\n          <div class=\\\\\\\"feature-card__desc\\\\\\\">Report problems with photo uploads, location details, and priority levels. Track resolution in real time.</div>\\\\n        </div>\\\\n        <div class=\\\\\\\"feature-card\\\\\\\">\\\\n          <div class=\\\\\\\"feature-card__icon\\\\\\\">&#128226;</div>\\\\n          <div class=\\\\\\\"feature-card__name\\\\\\\">Announcement Wall</div>\\\\n          <div class=\\\\\\\"feature-card__desc\\\\\\\">Board posts announcements with reactions and comments. Pin important notices. Replace those paper flyers.</div>\\\\n        </div>\\\\n      </div>\\\\n    </div>\\\\n  </section>\\\\n\\\\n  <!-- ======== PRICING ======== -->\\\\n  <section class=\\\\\\\"section section--cream section--dotted\\\\\\\" id=\\\\\\\"pricing\\\\\\\">\\\\n    <div class=\\\\\\\"container\\\\\\\">\\\\n      <div class=\\\\\\\"section-header section-header--center\\\\\\\">\\\\n        <p class=\\\\\\\"t-overline\\\\\\\">Pricing</p>\\\\n        <h2 class=\\\\\\\"t-display t-display--lg\\\\\\\">Flat pricing. No per-unit fees. Ever.</h2>\\\\n      </div>\\\\n\\\\n      <div class=\\\\\\\"plans-grid\\\\\\\">\\\\n        <div class=\\\\\\\"plan-card\\\\\\\">\\\\n          <div class=\\\\\\\"plan-card__name\\\\\\\">DIY Template</div>\\\\n          <div class=\\\\\\\"plan-card__price\\\\\\\">Free</div>\\\\n          <div class=\\\\\\\"plan-card__price-sub\\\\\\\">+ $5&ndash;20/mo Run402 hosting</div>\\\\n          <div class=\\\\\\\"plan-card__desc\\\\\\\">\\\\\\\"For developers and AI agents.\\\\\\\"</div>\\\\n          <ul class=\\\\\\\"plan-card__features\\\\\\\">\\\\n            <li>Full source code (open source)</li>\\\\n            <li>All features included</li>\\\\n            <li>Self-deploy to Run402</li>\\\\n            <li>Community support</li>\\\\n          </ul>\\\\n          <a href=\\\\\\\"https://github.com/kychee-com/wildlychee\\\\\\\" class=\\\\\\\"btn btn--outline\\\\\\\" target=\\\\\\\"_blank\\\\\\\">Fork on GitHub</a>\\\\n        </div>\\\\n\\\\n        <div class=\\\\\\\"plan-card plan-card--featured\\\\\\\">\\\\n          <div class=\\\\\\\"plan-card__name\\\\\\\">Studio Build</div>\\\\n          <div class=\\\\\\\"plan-card__price\\\\\\\">$29</div>\\\\n          <div class=\\\\\\\"plan-card__price-sub\\\\\\\">one-time + $5&ndash;20/mo hosting</div>\\\\n          <div class=\\\\\\\"plan-card__desc\\\\\\\">\\\\\\\"Tell us about your HOA. Live in 5 minutes.\\\\\\\"</div>\\\\n          <ul class=\\\\\\\"plan-card__features\\\\\\\">\\\\n            <li>AI investigates your existing site</li>\\\\n            <li>Guided interview &rarr; custom portal</li>\\\\n            <li>Brand colors, logo, content migrated</li>\\\\n            <li>Multi-language translation</li>\\\\n            <li>Chrome-verified deployment</li>\\\\n          </ul>\\\\n          <a href=\\\\\\\"#demo-placeholder\\\\\\\" class=\\\\\\\"btn btn--primary\\\\\\\">Build My Portal &rarr;</a>\\\\n        </div>\\\\n\\\\n        <div class=\\\\\\\"plan-card\\\\\\\">\\\\n          <div class=\\\\\\\"plan-card__name\\\\\\\">Lychee Pro</div>\\\\n          <div class=\\\\\\\"plan-card__price\\\\\\\">$9&ndash;29/mo</div>\\\\n          <div class=\\\\\\\"plan-card__price-sub\\\\\\\">ongoing, cancel anytime</div>\\\\n          <div class=\\\\\\\"plan-card__desc\\\\\\\">\\\\\\\"Your portal evolves with you.\\\\\\\"</div>\\\\n          <ul class=\\\\\\\"plan-card__features\\\\\\\">\\\\n            <li>Ongoing AI customization agent</li>\\\\n            <li>Feature requests via chat</li>\\\\n            <li>Priority support</li>\\\\n            <li>Advanced analytics</li>\\\\n          </ul>\\\\n          <a href=\\\\\\\"#demo-placeholder\\\\\\\" class=\\\\\\\"btn btn--outline\\\\\\\">Learn More</a>\\\\n        </div>\\\\n      </div>\\\\n    </div>\\\\n  </section>\\\\n\\\\n  <!-- ======== FINAL CTA ======== -->\\\\n  <section class=\\\\\\\"section section--indigo final-cta\\\\\\\">\\\\n    <div class=\\\\\\\"container\\\\\\\">\\\\n      <h2 class=\\\\\\\"t-display t-display--lg\\\\\\\">Ditch the email chains. Give your HOA a real portal.</h2>\\\\n      <p class=\\\\\\\"t-body--lg\\\\\\\">Open source. Flat pricing. AI-powered. Yours forever.</p>\\\\n      <div class=\\\\\\\"final-cta__buttons\\\\\\\">\\\\n        <a href=\\\\\\\"#demo-placeholder\\\\\\\" class=\\\\\\\"btn btn--white btn--lg\\\\\\\">Build Your HOA Portal &rarr;</a>\\\\n        <a href=\\\\\\\"https://github.com/kychee-com/wildlychee\\\\\\\" class=\\\\\\\"btn btn--outline btn--lg\\\\\\\" style=\\\\\\\"border-color:#fff;color:#fff\\\\\\\" target=\\\\\\\"_blank\\\\\\\">Fork on GitHub</a>\\\\n      </div>\\\\n    </div>\\\\n  </section>\\\\n\\\\n  <!-- ======== FOOTER ======== -->\\\\n  <footer class=\\\\\\\"footer\\\\\\\">\\\\n    <div class=\\\\\\\"container\\\\\\\">\\\\n      <p>\\\\n        <strong>Wild Lychee</strong> is open source. Built on <a href=\\\\\\\"https://run402.com\\\\\\\" target=\\\\\\\"_blank\\\\\\\">Run402</a>.\\\\n        &ensp;&middot;&ensp;\\\\n        <a href=\\\\\\\"https://github.com/kychee-com/wildlychee\\\\\\\" target=\\\\\\\"_blank\\\\\\\">GitHub</a>\\\\n        &ensp;&middot;&ensp;\\\\n        <a href=\\\\\\\"https://eagles.run402.com\\\\\\\" target=\\\\\\\"_blank\\\\\\\">Eagles Demo</a>\\\\n      </p>\\\\n    </div>\\\\n  </footer>\\\\n\\\\n  <!-- Mobile nav toggle -->\\\\n  <script>\\\\n    document.getElementById('nav-toggle')?.addEventListener('click', () => {\\\\n      document.getElementById('nav-links')?.classList.toggle('open');\\\\n    });\\\\n  </script>\\\\n\\\\n</body>\\\\n</html>\\\\n\\\"\\n    },\\n    {\\n      \\\"file\\\": \\\"index.html\\\",\\n      \\\"data\\\": \\\"<!DOCTYPE html>\\\\n<html lang=\\\\\\\"en\\\\\\\">\\\\n<head>\\\\n  <meta charset=\\\\\\\"UTF-8\\\\\\\">\\\\n  <meta name=\\\\\\\"viewport\\\\\\\" content=\\\\\\\"width=device-width, initial-scale=1.0\\\\\\\">\\\\n  <title>Wild Lychee вҖ” AI-Powered Community Portals</title>\\\\n  <meta name=\\\\\\\"description\\\\\\\" content=\\\\\\\"Open-source membership portal with AI features. Member directory, events, forum, newsletters вҖ” $5-20/mo. Own your data.\\\\\\\">\\\\n  <link rel=\\\\\\\"stylesheet\\\\\\\" href=\\\\\\\"/css/marketing.css\\\\\\\">\\\\n</head>\\\\n<body>\\\\n\\\\n  <!-- ======== NAV ======== -->\\\\n  <nav class=\\\\\\\"nav\\\\\\\">\\\\n    <div class=\\\\\\\"container nav__inner\\\\\\\">\\\\n      <a href=\\\\\\\"/\\\\\\\" class=\\\\\\\"nav__brand\\\\\\\">\\\\n        <span class=\\\\\\\"nav__brand-icon\\\\\\\">&#127819;</span>\\\\n        Wild Lychee\\\\n      </a>\\\\n      <button class=\\\\\\\"nav__toggle\\\\\\\" id=\\\\\\\"nav-toggle\\\\\\\" aria-label=\\\\\\\"Menu\\\\\\\">&#9776;</button>\\\\n      <div class=\\\\\\\"nav__links\\\\\\\" id=\\\\\\\"nav-links\\\\\\\">\\\\n        <a href=\\\\\\\"#features\\\\\\\" class=\\\\\\\"nav__link\\\\\\\">Features</a>\\\\n        <a href=\\\\\\\"#showcase\\\\\\\" class=\\\\\\\"nav__link\\\\\\\">Showcase</a>\\\\n        <a href=\\\\\\\"#pricing\\\\\\\" class=\\\\\\\"nav__link\\\\\\\">Pricing</a>\\\\n        <a href=\\\\\\\"#niches\\\\\\\" class=\\\\\\\"nav__link\\\\\\\">Who It's For</a>\\\\n        <a href=\\\\\\\"https://github.com/kychee-com/wildlychee\\\\\\\" class=\\\\\\\"nav__link\\\\\\\" target=\\\\\\\"_blank\\\\\\\">GitHub</a>\\\\n        <a href=\\\\\\\"#demo-placeholder\\\\\\\" class=\\\\\\\"btn btn--primary btn--lg nav__cta\\\\\\\">Try the Demo</a>\\\\n      </div>\\\\n    </div>\\\\n  </nav>\\\\n\\\\n  <!-- ======== HERO ======== -->\\\\n  <section class=\\\\\\\"hero section section--cream section--dotted\\\\\\\">\\\\n    <div class=\\\\\\\"container hero__content\\\\\\\">\\\\n      <p class=\\\\\\\"t-overline mb-2\\\\\\\">Open Source Community Platform</p>\\\\n      <h1 class=\\\\\\\"t-display t-display--xl hero__headline\\\\\\\">\\\\n        Your community deserves better than <em>Wild Apricot</em>.\\\\n      </h1>\\\\n      <p class=\\\\\\\"t-body--lg hero__sub\\\\\\\">\\\\n        Wild Lychee is an AI-powered membership portal you actually own. Member directory, events, forum, announcements, newsletters &mdash; all for <strong style=\\\\\\\"color:var(--ink)\\\\\\\">$5&ndash;20/mo</strong> on your own infrastructure. No per-member fees. No lock-in. No surprise price hikes.\\\\n      </p>\\\\n      <div class=\\\\\\\"hero__ctas\\\\\\\">\\\\n        <a href=\\\\\\\"#demo-placeholder\\\\\\\" class=\\\\\\\"btn btn--primary btn--lg\\\\\\\">Try the Demo &rarr;</a>\\\\n        <a href=\\\\\\\"#showcase\\\\\\\" class=\\\\\\\"btn btn--outline btn--lg\\\\\\\">See It Live</a>\\\\n        <a href=\\\\\\\"https://github.com/kychee-com/wildlychee\\\\\\\" class=\\\\\\\"btn btn--ghost btn--lg\\\\\\\" target=\\\\\\\"_blank\\\\\\\">Fork on GitHub</a>\\\\n      </div>\\\\n    </div>\\\\n    <div class=\\\\\\\"hero__aside\\\\\\\" aria-hidden=\\\\\\\"true\\\\\\\"></div>\\\\n  </section>\\\\n\\\\n  <!-- ======== THE PROBLEM ======== -->\\\\n  <section class=\\\\\\\"section section--white\\\\\\\">\\\\n    <div class=\\\\\\\"container\\\\\\\">\\\\n      <div class=\\\\\\\"section-header section-header--center\\\\\\\">\\\\n        <p class=\\\\\\\"t-overline\\\\\\\">The Problem</p>\\\\n        <h2 class=\\\\\\\"t-display t-display--lg\\\\\\\">Community software is a racket.</h2>\\\\n      </div>\\\\n\\\\n      <div class=\\\\\\\"problem-grid\\\\\\\">\\\\n        <div class=\\\\\\\"problem-card\\\\\\\">\\\\n          <div class=\\\\\\\"problem-card__name\\\\\\\">Wild Apricot</div>\\\\n          <div class=\\\\\\\"problem-card__price\\\\\\\">$530/mo</div>\\\\n          <div class=\\\\\\\"problem-card__desc\\\\\\\">At 2,000 members. For a glorified spreadsheet with a 2008 UI.</div>\\\\n        </div>\\\\n        <div class=\\\\\\\"problem-card\\\\\\\">\\\\n          <div class=\\\\\\\"problem-card__name\\\\\\\">Circle</div>\\\\n          <div class=\\\\\\\"problem-card__price\\\\\\\">$89/mo + fees</div>\\\\n          <div class=\\\\\\\"problem-card__desc\\\\\\\">Per-seat pricing. And they just raised prices. Again.</div>\\\\n        </div>\\\\n        <div class=\\\\\\\"problem-card\\\\\\\">\\\\n          <div class=\\\\\\\"problem-card__name\\\\\\\">Bettermode</div>\\\\n          <div class=\\\\\\\"problem-card__price\\\\\\\">Price hikes yearly</div>\\\\n          <div class=\\\\\\\"problem-card__desc\\\\\\\">Your data locked behind their API. Good luck migrating.</div>\\\\n        </div>\\\\n      </div>\\\\n\\\\n      <div class=\\\\\\\"problem-transition\\\\\\\">\\\\n        <p class=\\\\\\\"problem-transition__what-if\\\\\\\">What if you could just&hellip; own it?</p>\\\\n        <p class=\\\\\\\"t-body\\\\\\\">An open-source portal that runs on your infrastructure, costs a flat $5&ndash;20/mo regardless of member count, and lets an AI agent customize it for you. That's Wild Lychee.</p>\\\\n      </div>\\\\n    </div>\\\\n  </section>\\\\n\\\\n  <!-- ======== FEATURES ======== -->\\\\n  <section class=\\\\\\\"section section--cream section--dotted\\\\\\\" id=\\\\\\\"features\\\\\\\">\\\\n    <div class=\\\\\\\"container\\\\\\\">\\\\n      <div class=\\\\\\\"section-header\\\\\\\">\\\\n        <p class=\\\\\\\"t-overline\\\\\\\">Everything You Need</p>\\\\n        <h2 class=\\\\\\\"t-display t-display--lg\\\\\\\">One template. Every feature.</h2>\\\\n        <p class=\\\\\\\"t-body--lg mt-2\\\\\\\">All features ship. Toggle them on with a config flag. No plugins, no marketplace, no upsells.</p>\\\\n      </div>\\\\n\\\\