      "file": "capture-screenshots.sh",
      "data": "#!/usr/bin/env zsh\n# ============================================\n# Capture showcase screenshots for marketing site\n# Uses Chrome headless mode (no dependencies needed)\n#\n# Usage:\n#   ./marketing/capture-screenshots.sh          # all sites\n#   ./marketing/capture-screenshots.sh eagles   # just eagles\n# ============================================\n\nset -e\n\nSCRIPT_DIR=\"${0:a:h}\"\nASSETS_DIR=\"$SCRIPT_DIR/assets\"\nmkdir -p \"$ASSETS_DIR\"\n\n# Find Chrome\nif [[ -d \"/Applications/Google Chrome.app\" ]]; then\n  CHROME=\"/Applications/Google Chrome.app/Contents/MacOS/Google Chrome\"\nelif (( $+commands[google-chrome] )); then\n  CHROME=\"google-chrome\"\nelif (( $+commands[chromium] )); then\n  CHROME=\"chromium\"\nelse\n  echo \"Chrome not found. Install Google Chrome.\"\n  exit 1\nfi\n\nWIDTH=1280\nHEIGHT=800\n\ncapture() {\n  local name=\"$1\"\n  local url=\"$2\"\n  local output=\"$ASSETS_DIR/screenshot-${name}.png\"\n\n  echo \"Capturing $name ($url)...\"\n  # Use a small HTML page that navigates to the URL, waits for JS to render, then screenshots\n  local tmphtml=$(mktemp /tmp/capture-XXXXXX.html)\n  cat > \"$tmphtml\" <<HTMLEOF\n<!DOCTYPE html>\n<html><body><script>\n  // Navigate and wait for content to load\n  window.location = '$url';\n</script></body></html>\nHTMLEOF\n\n  # Use virtual-time-budget to let JS execute (5 seconds of simulated time)\n  \"$CHROME\" \\\n    --headless=new \\\n    --disable-gpu \\\n    --no-sandbox \\\n    --hide-scrollbars \\\n    --window-size=\"${WIDTH},${HEIGHT}\" \\\n    --virtual-time-budget=8000 \\\n    --screenshot=\"$output\" \\\n    \"$url\" \\\n    2>/dev/null\n\n  rm -f \"$tmphtml\"\n\n  if [[ -f \"$output\" ]]; then\n    local size=$(du -h \"$output\" | cut -f1)\n    echo \"  Saved: $output ($size)\"\n  else\n    echo \"  FAILED: $output not created\"\n  fi\n}\n\n# Showcase sites вҖ” add more as they're created\ntypeset -A SITES\nSITES=(\n  eagles          \"https://eagles.run402.com\"\n  eagles-directory \"https://eagles.run402.com/directory.html\"\n  eagles-events   \"https://eagles.run402.com/events.html\"\n  eagles-forum    \"https://eagles.run402.com/forum.html\"\n)\n\nif [[ -n \"$1\" ]]; then\n  if [[ -n \"${SITES[$1]}\" ]]; then\n    capture \"$1\" \"${SITES[$1]}\"\n  else\n    echo \"Unknown site: $1\"\n    echo \"Available: ${(k)SITES}\"\n    exit 1\n  fi\nelse\n  for name url in \"${(@kv)SITES}\"; do\n    capture \"$name\" \"$url\"\n  done\nfi\n\necho \"Done.\"\n"
