      "data": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Wild Lychee vs Wild Apricot, Circle, Bettermode вҖ” Pricing Comparison</title>\n  <meta name=\"description\" content=\"Compare Wild Lychee pricing and features against Wild Apricot, Circle, and Bettermode. Flat $5-20/mo vs per-member pricing.\">\n  <link rel=\"stylesheet\" href=\"/css/marketing.css\">\n</head>\n<body>\n\n  <!-- ======== NAV ======== -->\n  <nav class=\"nav\">\n    <div class=\"container nav__inner\">\n      <a href=\"/\" class=\"nav__brand\">\n        <span class=\"nav__brand-icon\">&#127819;</span>\n        Wild Lychee\n      </a>\n      <button class=\"nav__toggle\" id=\"nav-toggle\" aria-label=\"Menu\">&#9776;</button>\n      <div class=\"nav__links\" id=\"nav-links\">\n        <a href=\"/\" class=\"nav__link\">&larr; Back to Wild Lychee</a>\n        <a href=\"/#features\" class=\"nav__link\">Features</a>\n        <a href=\"/#pricing\" class=\"nav__link\">Pricing</a>\n        <a href=\"https://github.com/kychee-com/wildlychee\" class=\"nav__link\" target=\"_blank\">GitHub</a>\n        <a href=\"https://eagles.run402.com\" class=\"btn btn--primary btn--lg nav__cta\" target=\"_blank\">Explore Live Demo</a>\n      </div>\n    </div>\n  </nav>\n\n  <!-- ======== HERO ======== -->\n  <section class=\"hero section section--cream\" style=\"padding:5rem 0 3rem\">\n    <div class=\"container\" style=\"text-align:center\">\n      <p class=\"t-overline mb-2\">Pricing Comparison</p>\n      <h1 class=\"t-display t-display--xl\" style=\"max-width:44rem;margin:0 auto 1.5rem\">\n        How Wild Lychee compares.\n      </h1>\n      <p class=\"t-body--lg\" style=\"max-width:38rem;margin:0 auto\">\n        Community software doesn't have to cost hundreds per month. Here's how Wild Lychee stacks up against the incumbents.\n      </p>\n    </div>\n  </section>\n\n  <!-- ======== PRICING TABLE ======== -->\n  <section class=\"section section--white\">\n    <div class=\"container\">\n      <div class=\"section-header section-header--center\">\n        <h2 class=\"t-display t-display--lg\">Monthly cost by member count</h2>\n        <p class=\"t-body--lg mt-2\" style=\"margin-left:auto;margin-right:auto;\">Wild Lychee charges for hosting, not members. Your cost stays flat as you grow.</p>\n      </div>\n\n      <div class=\"pricing-comparison\">\n        <table class=\"pricing-table\">\n          <thead>\n            <tr>\n              <th>Members</th>\n              <th>Wild Apricot</th>\n              <th>Circle</th>\n              <th>Bettermode</th>\n              <th>Wild Lychee</th>\n            </tr>\n          </thead>\n          <tbody>\n            <tr>\n              <td>100</td>\n              <td class=\"pricing-table__muted\">$100/mo</td>\n              <td class=\"pricing-table__muted\">$89/mo</td>\n              <td class=\"pricing-table__muted\">$79/mo</td>\n              <td class=\"pricing-table__highlight\">$5/mo</td>\n            </tr>\n            <tr>\n              <td>500</td>\n              <td class=\"pricing-table__muted\">$200/mo</td>\n              <td class=\"pricing-table__muted\">$89/mo</td>\n              <td class=\"pricing-table__muted\">$199/mo</td>\n              <td class=\"pricing-table__highlight\">$5/mo</td>\n            </tr>\n            <tr>\n              <td>2,000</td>\n              <td class=\"pricing-table__muted\">$530/mo</td>\n              <td class=\"pricing-table__muted\">$219/mo</td>\n              <td class=\"pricing-table__muted\">$399/mo</td>\n              <td class=\"pricing-table__highlight\">$10/mo</td>\n            </tr>\n            <tr>\n              <td>5,000</td>\n              <td class=\"pricing-table__muted\">$900/mo</td>\n              <td class=\"pricing-table__muted\">$399/mo</td>\n              <td class=\"pricing-table__muted\">$599/mo</td>\n              <td class=\"pricing-table__highlight\">$20/mo</td>\n            </tr>\n          </tbody>\n        </table>\n      </div>\n\n      <p class=\"t-body--sm\" style=\"text-align:center;color:var(--ink-subtle)\">Competitor pricing based on publicly listed plans as of March 2026. Wild Lychee pricing is Run402 hosting cost.</p>\n    </div>\n  </section>\n\n  <!-- ======== FEATURE COMPARISON ======== -->\n  <section class=\"section section--cream\">\n    <div class=\"container\">\n      <div class=\"section-header section-header--center\">\n        <h2 class=\"t-display t-display--lg\">Feature comparison</h2>\n      </div>\n\n      <div class=\"pricing-comparison\">\n        <table class=\"pricing-table\">\n          <thead>\n            <tr>\n              <th>Feature</th>\n              <th>Wild Apricot</th>\n              <th>Circle</th>\n              <th>Wild Lychee</th>\n            </tr>\n          </thead>\n          <tbody>\n            <tr><td>Member directory</td><td>&#10003;</td><td>&#10003;</td><td class=\"pricing-table__highlight\">&#10003;</td></tr>\n            <tr><td>Events &amp; RSVP</td><td>&#10003;</td><td>Limited</td><td class=\"pricing-table__highlight\">&#10003;</td></tr>\n            <tr><td>Forum / discussions</td><td>&#10007;</td><td>&#10003;</td><td class=\"pricing-table__highlight\">&#10003;</td></tr>\n            <tr><td>Resource library</td><td>Limited</td><td>&#10007;</td><td class=\"pricing-table__highlight\">&#10003;</td></tr>\n            <tr><td>Committees / groups</td><td>&#10007;</td><td>&#10003;</td><td class=\"pricing-table__highlight\">&#10003;</td></tr>\n            <tr><td>Inline editing</td><td>&#10007;</td><td>&#10007;</td><td class=\"pricing-table__highlight\">&#10003;</td></tr>\n            <tr><td>AI moderation</td><td>&#10007;</td><td>&#10007;</td><td class=\"pricing-table__highlight\">&#10003;</td></tr>\n            <tr><td>AI translation</td><td>&#10007;</td><td>&#10007;</td><td class=\"pricing-table__highlight\">&#10003;</td></tr>\n            <tr><td>AI newsletter</td><td>&#10007;</td><td>&#10007;</td><td class=\"pricing-table__highlight\">&#10003;</td></tr>\n            <tr><td>Open source</td><td>&#10007;</td><td>&#10007;</td><td class=\"pricing-table__highlight\">&#10003;</td></tr>\n            <tr><td>Own your data</td><td>&#10007;</td><td>&#10007;</td><td class=\"pricing-table__highlight\">&#10003;</td></tr>\n            <tr><td>Per-member fees</td><td>Yes</td><td>Yes</td><td class=\"pricing-table__highlight\">Never</td></tr>\n          </tbody>\n        </table>\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== MIGRATION ======== -->\n  <section class=\"section section--white\">\n    <div class=\"container\" style=\"text-align:center;max-width:36rem\">\n      <h2 class=\"t-display t-display--md mb-3\">Ready to switch?</h2>\n      <p class=\"t-body mb-4\">Lychee Studio can investigate your existing site and migrate your branding, colors, and content structure in minutes. Member data can be imported via CSV.</p>\n      <div style=\"display:flex;gap:0.75rem;justify-content:center;flex-wrap:wrap\">\n        <a href=\"https://eagles.run402.com\" class=\"btn btn--primary btn--lg\" target=\"_blank\">Explore the Demo &rarr;</a>\n        <a href=\"/\" class=\"btn btn--outline btn--lg\">Back to Wild Lychee</a>\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== FOOTER ======== -->\n  <footer class=\"footer\">\n    <div class=\"container\">\n      <p>\n        <strong>Wild Lychee</strong> is open source. Built on <a href=\"https://run402.com\" target=\"_blank\">Run402</a>.\n        &ensp;&middot;&ensp;\n        <a href=\"https://github.com/kychee-com/wildlychee\" target=\"_blank\">GitHub</a>\n        &ensp;&middot;&ensp;\n        <a href=\"https://eagles.run402.com\" target=\"_blank\">Eagles Demo</a>\n      </p>\n    </div>\n  </footer>\n\n  <script>\n    document.getElementById('nav-toggle')?.addEventListener('click', () => {\n      document.getElementById('nav-links')?.classList.toggle('open');\n    });\n  </script>\n\n</body>\n</html>\n"
