      "file": "index.html",
      "data": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Wild Lychee вҖ” Own Your Member Portal</title>\n  <meta name=\"description\" content=\"Open-source membership portal with AI features. Member directory, events, forum, newsletters вҖ” $5-20/mo. Own your data, own your platform.\">\n  <link rel=\"stylesheet\" href=\"/css/marketing.css\">\n</head>\n<body>\n\n  <!-- ======== NAV ======== -->\n  <nav class=\"nav\">\n    <div class=\"container nav__inner\">\n      <a href=\"/\" class=\"nav__brand\">\n        <span class=\"nav__brand-icon\">&#127819;</span>\n        Wild Lychee\n      </a>\n      <button class=\"nav__toggle\" id=\"nav-toggle\" aria-label=\"Menu\">&#9776;</button>\n      <div class=\"nav__links\" id=\"nav-links\">\n        <a href=\"#showcase\" class=\"nav__link\">Demo</a>\n        <a href=\"#features\" class=\"nav__link\">Features</a>\n        <a href=\"#pricing\" class=\"nav__link\">Pricing</a>\n        <a href=\"#niches\" class=\"nav__link\">Who It's For</a>\n        <a href=\"https://github.com/kychee-com/wildlychee\" class=\"nav__link\" target=\"_blank\">GitHub</a>\n        <a href=\"https://eagles.run402.com\" class=\"btn btn--primary btn--lg nav__cta\" target=\"_blank\">Explore Live Demo</a>\n      </div>\n    </div>\n  </nav>\n\n  <!-- ======== HERO ======== -->\n  <section class=\"hero section section--cream section--dotted\">\n    <div class=\"container\" style=\"text-align:center\">\n      <p class=\"t-overline mb-2\">Open Source Community Platform</p>\n      <h1 class=\"t-display t-display--xl hero__headline\" style=\"max-width:44rem;margin:0 auto 1.5rem\">\n        Own your <em>member portal</em>.\n      </h1>\n      <p class=\"t-body--lg hero__sub\" style=\"max-width:38rem;margin:0 auto 2.5rem\">\n        Wild Lychee gives associations, clubs, churches, and HOAs a complete portal &mdash; member directory, events, forum, announcements, and resources &mdash; on software you control, for <strong style=\"color:var(--ink)\">$5&ndash;20/mo</strong>.\n      </p>\n      <div class=\"hero__ctas\" style=\"justify-content:center\">\n        <a href=\"https://eagles.run402.com\" class=\"btn btn--primary btn--lg\" target=\"_blank\">Explore Live Demo &rarr;</a>\n        <a href=\"#pricing\" class=\"btn btn--outline btn--lg\">Get a Custom Build &mdash; $29</a>\n        <a href=\"https://github.com/kychee-com/wildlychee\" class=\"btn btn--ghost btn--lg\" target=\"_blank\">View on GitHub</a>\n      </div>\n      <p class=\"t-body--sm mt-2\" style=\"color:var(--ink-subtle)\">No signup required &middot; Real portal, sample content</p>\n\n      <div class=\"browser-mockup\">\n        <div class=\"browser-mockup__chrome\">\n          <div class=\"browser-mockup__dots\"><span></span><span></span><span></span></div>\n          <div class=\"browser-mockup__url\">eagles.run402.com</div>\n        </div>\n        <img src=\"/assets/screenshot-eagles.png\" alt=\"Eagles community portal вҖ” a fully populated Wild Lychee demo\">\n      </div>\n\n      <div class=\"hero__stats\">\n        <span class=\"hero__stat\"><span class=\"hero__stat-dot\"></span> 25 members</span>\n        <span class=\"hero__stat\"><span class=\"hero__stat-dot\"></span> 10 events</span>\n        <span class=\"hero__stat\"><span class=\"hero__stat-dot\"></span> Active forum</span>\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== PRODUCT TOUR ======== -->\n  <section class=\"section section--white\" id=\"showcase\">\n    <div class=\"container\">\n      <div class=\"section-header section-header--center\">\n        <p class=\"t-overline\">See It Live</p>\n        <h2 class=\"t-display t-display--lg\">Tour a real portal.</h2>\n        <p class=\"t-body--lg mt-2\" style=\"margin-left:auto;margin-right:auto;\">Browse a fully populated demo &mdash; members, events, forum, announcements, reactions, activity feed. No signup required.</p>\n      </div>\n\n      <div class=\"tour-grid\">\n        <a href=\"https://eagles.run402.com\" target=\"_blank\" class=\"tour-tile\">\n          <div class=\"tour-tile__img\">\n            <img src=\"/assets/screenshot-eagles.png\" alt=\"Eagles homepage\">\n          </div>\n          <div class=\"tour-tile__body\">\n            <span class=\"tour-tile__name\">Homepage &amp; Activity Feed</span>\n            <span class=\"tour-tile__link\">Browse &rarr;</span>\n          </div>\n        </a>\n        <a href=\"https://eagles.run402.com/directory.html\" target=\"_blank\" class=\"tour-tile\">\n          <div class=\"tour-tile__img\">\n            <img src=\"/assets/screenshot-eagles-directory.png\" alt=\"Member directory\">\n          </div>\n          <div class=\"tour-tile__body\">\n            <span class=\"tour-tile__name\">Member Directory</span>\n            <span class=\"tour-tile__link\">Browse &rarr;</span>\n          </div>\n        </a>\n        <a href=\"https://eagles.run402.com/events.html\" target=\"_blank\" class=\"tour-tile\">\n          <div class=\"tour-tile__img\">\n            <img src=\"/assets/screenshot-eagles-events.png\" alt=\"Events and RSVP\">\n          </div>\n          <div class=\"tour-tile__body\">\n            <span class=\"tour-tile__name\">Events &amp; RSVP</span>\n            <span class=\"tour-tile__link\">Browse &rarr;</span>\n          </div>\n        </a>\n        <a href=\"https://eagles.run402.com/forum.html\" target=\"_blank\" class=\"tour-tile\">\n          <div class=\"tour-tile__img\">\n            <img src=\"/assets/screenshot-eagles-forum.png\" alt=\"Forum discussions\">\n          </div>\n          <div class=\"tour-tile__body\">\n            <span class=\"tour-tile__name\">Forum Discussions</span>\n            <span class=\"tour-tile__link\">Browse &rarr;</span>\n          </div>\n        </a>\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== BENEFITS ======== -->\n  <section class=\"section section--cream\">\n    <div class=\"container\">\n      <div class=\"section-header section-header--center\">\n        <p class=\"t-overline\">Why Wild Lychee</p>\n        <h2 class=\"t-display t-display--lg\">Why organizations choose Wild Lychee.</h2>\n      </div>\n\n      <div class=\"benefits-grid\">\n        <div class=\"benefit-card\">\n          <div class=\"benefit-card__icon\">&#128176;</div>\n          <div class=\"benefit-card__title\">Predictable cost</div>\n          <div class=\"benefit-card__desc\">No per-member fees. $5&ndash;20/mo flat, whether you have 50 members or 5,000. The price scales with your hosting tier, not your headcount.</div>\n        </div>\n        <div class=\"benefit-card\">\n          <div class=\"benefit-card__icon\">&#128274;</div>\n          <div class=\"benefit-card__title\">You own everything</div>\n          <div class=\"benefit-card__desc\">Your data, your branding, your domain. Open source &mdash; fork it, modify it, it's yours. No lock-in, no export fees, no surprises.</div>\n        </div>\n        <div class=\"benefit-card\">\n          <div class=\"benefit-card__icon\">&#129302;</div>\n          <div class=\"benefit-card__title\">AI does the work</div>\n          <div class=\"benefit-card__desc\">Studio builds your portal in 5 minutes. Pro keeps it evolving with ongoing AI customization. Or customize it yourself &mdash; it's just HTML and SQL.</div>\n        </div>\n      </div>\n\n      <div class=\"compare-link\">\n        Switching from Wild Apricot, Circle, or Bettermode? <a href=\"/compare.html\">See the full comparison.</a>\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== HOW IT WORKS ======== -->\n  <section class=\"section section--white\">\n    <div class=\"container\">\n      <div class=\"section-header section-header--center\">\n        <p class=\"t-overline\">Get Started</p>\n        <h2 class=\"t-display t-display--lg\">How it works.</h2>\n      </div>\n\n      <div class=\"steps-grid\">\n        <div class=\"step-card\">\n          <div class=\"step-card__number\">1</div>\n          <div class=\"step-card__title\">Pick a template</div>\n          <div class=\"step-card__desc\">Choose your community type &mdash; church, HOA, sports league, association &mdash; or start with the default.</div>\n        </div>\n        <div class=\"step-card\">\n          <div class=\"step-card__number\">2</div>\n          <div class=\"step-card__title\">AI builds your portal</div>\n          <div class=\"step-card__desc\">Studio investigates your existing site, asks a few questions, and generates a custom portal in minutes.</div>\n        </div>\n        <div class=\"step-card\">\n          <div class=\"step-card__number\">3</div>\n          <div class=\"step-card__title\">Launch and customize</div>\n          <div class=\"step-card__desc\">Deploy to your domain. Edit content inline. Toggle features on and off. It's yours.</div>\n        </div>\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== FEATURES ======== -->\n  <section class=\"section section--cream section--dotted\" id=\"features\">\n    <div class=\"container\">\n      <div class=\"section-header\">\n        <p class=\"t-overline\">Everything You Need</p>\n        <h2 class=\"t-display t-display--lg\">One template. Every feature.</h2>\n        <p class=\"t-body--lg mt-2\">All features ship. Toggle them on with a config flag. No plugins, no marketplace, no upsells.</p>\n      </div>\n\n      <div class=\"feature-grid\">\n        <div class=\"feature-card\">\n          <div class=\"feature-card__icon\">&#128101;</div>\n          <div class=\"feature-card__name\">Member Directory</div>\n          <div class=\"feature-card__desc\">Searchable profiles with custom fields, tiers, and role-based access.</div>\n        </div>\n        <div class=\"feature-card\">\n          <div class=\"feature-card__icon\">&#128197;</div>\n          <div class=\"feature-card__name\">Events &amp; RSVP</div>\n          <div class=\"feature-card__desc\">Calendar with capacity tracking, reminders, and attendee management.</div>\n        </div>\n        <div class=\"feature-card\">\n          <div class=\"feature-card__icon\">&#128226;</div>\n          <div class=\"feature-card__name\">Announcements</div>\n          <div class=\"feature-card__desc\">Rich text posts with emoji reactions. Pin the important ones.</div>\n        </div>\n        <div class=\"feature-card\">\n          <div class=\"feature-card__icon\">&#128218;</div>\n          <div class=\"feature-card__name\">Resource Library</div>\n          <div class=\"feature-card__desc\">Files, links, and documents with member-only access control.</div>\n        </div>\n        <div class=\"feature-card\">\n          <div class=\"feature-card__icon\">&#128172;</div>\n          <div class=\"feature-card__name\">Forum</div>\n          <div class=\"feature-card__desc\">Categories, topics, threaded replies, and moderation tools.</div>\n        </div>\n        <div class=\"feature-card\">\n          <div class=\"feature-card__icon\">&#127963;&#65039;</div>\n          <div class=\"feature-card__name\">Committees</div>\n          <div class=\"feature-card__desc\">Working groups with roles, member assignments, and descriptions.</div>\n        </div>\n        <div class=\"feature-card\">\n          <div class=\"feature-card__icon\">&#9999;&#65039;</div>\n          <div class=\"feature-card__name\">Inline Editing</div>\n          <div class=\"feature-card__desc\">The page IS the admin panel. Click to edit, no separate dashboard.</div>\n        </div>\n        <div class=\"feature-card\">\n          <div class=\"feature-card__icon\">&#9889;</div>\n          <div class=\"feature-card__name\">Config-Driven</div>\n          <div class=\"feature-card__desc\">Restructure your entire site with SQL. No code changes needed.</div>\n        </div>\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== AI FEATURES ======== -->\n  <section class=\"section ai-section\" id=\"ai\">\n    <div class=\"container\">\n      <div class=\"section-header\">\n        <p class=\"t-overline\">AI-Powered</p>\n        <h2 class=\"t-display t-display--lg\">Six AI features. Your API key.</h2>\n        <p class=\"t-body--lg mt-2\">Every AI feature is optional, bring-your-own-key, and runs on your schedule. No vendor lock-in. No surprise bills from us.</p>\n      </div>\n\n      <div class=\"ai-grid\">\n        <div class=\"ai-card\">\n          <div class=\"ai-card__icon\">&#128737;&#65039;</div>\n          <div class=\"ai-card__name\">Content Moderation</div>\n          <div class=\"ai-card__desc\">Auto-flag spam and toxicity. Review queue for admins. Runs every 15 minutes.</div>\n        </div>\n        <div class=\"ai-card\">\n          <div class=\"ai-card__icon\">&#127760;</div>\n          <div class=\"ai-card__name\">Auto-Translation</div>\n          <div class=\"ai-card__desc\">Publish once, serve in any language. Triggered on content publish.</div>\n        </div>\n        <div class=\"ai-card\">\n          <div class=\"ai-card__icon\">&#128240;</div>\n          <div class=\"ai-card__name\">Newsletter Writer</div>\n          <div class=\"ai-card__desc\">AI drafts your weekly update from recent activity. You approve and send.</div>\n        </div>\n        <div class=\"ai-card\">\n          <div class=\"ai-card__icon\">&#127919;</div>\n          <div class=\"ai-card__name\">Smart Onboarding</div>\n          <div class=\"ai-card__desc\">Personalized welcome message for each new member based on their profile.</div>\n        </div>\n        <div class=\"ai-card\">\n          <div class=\"ai-card__icon\">&#128202;</div>\n          <div class=\"ai-card__name\">Member Insights</div>\n          <div class=\"ai-card__desc\">Spot at-risk members before they leave. Daily analysis of engagement patterns.</div>\n        </div>\n        <div class=\"ai-card\">\n          <div class=\"ai-card__icon\">&#128221;</div>\n          <div class=\"ai-card__name\">Event Recaps</div>\n          <div class=\"ai-card__desc\">AI writes the post-event summary from attendance and photos. You approve it.</div>\n        </div>\n      </div>\n\n      <div class=\"ai-byok\">\n        &#128273;&ensp; Bring your own API key. Your AI, your cost, your control.\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== WHO IT'S FOR ======== -->\n  <section class=\"section section--cream\" id=\"niches\">\n    <div class=\"container\">\n      <div class=\"section-header section-header--center\">\n        <p class=\"t-overline\">Who It's For</p>\n        <h2 class=\"t-display t-display--lg\">Built for communities of every kind.</h2>\n        <p class=\"t-body--lg mt-2\" style=\"margin-left:auto;margin-right:auto;\">Wild Lychee adapts to your community type with niche-specific templates, features, and seed data.</p>\n      </div>\n\n      <div class=\"niche-grid\">\n        <a href=\"/churches.html\" class=\"niche-card\">\n          <div class=\"niche-card__icon\">&#9961;</div>\n          <div class=\"niche-card__name\">Churches &amp; Religious Orgs</div>\n          <div class=\"niche-card__sub\">Sermons, prayer requests, small groups</div>\n        </a>\n        <a href=\"/associations.html\" class=\"niche-card\">\n          <div class=\"niche-card__icon\">&#127970;</div>\n          <div class=\"niche-card__name\">Professional Associations</div>\n          <div class=\"niche-card__sub\">Directory, committees, conferences</div>\n        </a>\n        <a href=\"/sports.html\" class=\"niche-card\">\n          <div class=\"niche-card__icon\">&#9917;</div>\n          <div class=\"niche-card__name\">Sports Leagues &amp; Clubs</div>\n          <div class=\"niche-card__sub\">Rosters, schedules, standings</div>\n        </a>\n        <a href=\"/hoa.html\" class=\"niche-card\">\n          <div class=\"niche-card__icon\">&#127968;</div>\n          <div class=\"niche-card__name\">HOAs &amp; Condos</div>\n          <div class=\"niche-card__sub\">Maintenance, documents, voting</div>\n        </a>\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== PRICING ======== -->\n  <section class=\"section section--white\" id=\"pricing\">\n    <div class=\"container\">\n      <div class=\"section-header section-header--center\">\n        <p class=\"t-overline\">Pricing</p>\n        <h2 class=\"t-display t-display--lg\">Simple, transparent pricing.</h2>\n      </div>\n\n      <div class=\"plans-grid\">\n        <div class=\"plan-card\">\n          <div class=\"plan-card__name\">DIY Template</div>\n          <div class=\"plan-card__price\">Free</div>\n          <div class=\"plan-card__price-sub\">+ $5&ndash;20/mo Run402 hosting</div>\n          <div class=\"plan-card__desc\">\"For developers and AI agents.\"</div>\n          <ul class=\"plan-card__features\">\n            <li>Full source code (open source)</li>\n            <li>All features included</li>\n            <li>Self-deploy to Run402</li>\n            <li>Community support</li>\n          </ul>\n          <a href=\"https://github.com/kychee-com/wildlychee\" class=\"btn btn--outline\" target=\"_blank\">Fork on GitHub</a>\n        </div>\n\n        <div class=\"plan-card plan-card--featured\">\n          <div class=\"plan-card__name\">Studio Build</div>\n          <div class=\"plan-card__price\">$29</div>\n          <div class=\"plan-card__price-sub\">one-time + $5&ndash;20/mo hosting</div>\n          <div class=\"plan-card__desc\">\"Tell us about your community. Live in 5 minutes.\"</div>\n          <ul class=\"plan-card__features\">\n            <li>AI investigates your existing site</li>\n            <li>Guided interview &rarr; custom portal</li>\n            <li>Brand colors, logo, content migrated</li>\n            <li>Multi-language translation</li>\n            <li>Chrome-verified deployment</li>\n          </ul>\n          <a href=\"https://eagles.run402.com\" class=\"btn btn--primary\" target=\"_blank\">See a Demo First &rarr;</a>\n        </div>\n\n        <div class=\"plan-card\">\n          <div class=\"plan-card__name\">Lychee Pro</div>\n          <div class=\"plan-card__price\">$9&ndash;29/mo</div>\n          <div class=\"plan-card__price-sub\">ongoing, cancel anytime</div>\n          <div class=\"plan-card__desc\">\"Your portal evolves with you.\"</div>\n          <ul class=\"plan-card__features\">\n            <li>Ongoing AI customization agent</li>\n            <li>Feature requests via chat</li>\n            <li>Priority support</li>\n            <li>Advanced analytics</li>\n          </ul>\n          <a href=\"https://eagles.run402.com\" class=\"btn btn--outline\" target=\"_blank\">Explore Demo</a>\n        </div>\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== FAQ ======== -->\n  <section class=\"section section--cream\" id=\"faq\">\n    <div class=\"container\">\n      <div class=\"section-header section-header--center\">\n        <p class=\"t-overline\">FAQ</p>\n        <h2 class=\"t-display t-display--lg\">Questions? We've got answers.</h2>\n      </div>\n\n      <div class=\"faq-list\">\n        <details class=\"faq-item\">\n          <summary>Is it really $5&ndash;20/mo?</summary>\n          <p>Yes. Wild Lychee is open-source software. The $5&ndash;20/mo covers Run402 hosting (database, file storage, edge functions, subdomain). There are no per-member fees, no usage charges, and no hidden costs. The price scales with your hosting tier, not your member count.</p>\n        </details>\n        <details class=\"faq-item\">\n          <summary>Do I need technical skills?</summary>\n          <p>Not with Studio. Tell us about your community, and AI builds your portal in minutes. For the DIY template, basic comfort with deploying web apps is helpful &mdash; but AI agents can handle that too.</p>\n        </details>\n        <details class=\"faq-item\">\n          <summary>Who owns the data?</summary>\n          <p>You do. Wild Lychee runs on your own Run402 project with your own database. You can export, migrate, or delete at any time. We never touch your data.</p>\n        </details>\n        <details class=\"faq-item\">\n          <summary>Can I migrate from Wild Apricot or Circle?</summary>\n          <p>Yes. Studio can investigate your existing site and migrate your branding, colors, and content structure. Member data can be imported via CSV. See our <a href=\"/compare.html\">comparison page</a> for details.</p>\n        </details>\n        <details class=\"faq-item\">\n          <summary>What does &ldquo;AI-powered&rdquo; actually mean?</summary>\n          <p>Six optional AI features run on your own API key (OpenAI or Anthropic): content moderation, auto-translation, newsletter drafts, smart onboarding, member insights, and event recaps. You control what runs, when, and at what cost.</p>\n        </details>\n        <details class=\"faq-item\">\n          <summary>Why is it so affordable?</summary>\n          <p>Because Wild Lychee is open source and runs on Run402's serverless infrastructure. There's no sales team, no enterprise licensing, and no per-seat revenue model. You pay for hosting, not for software.</p>\n        </details>\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== FINAL CTA ======== -->\n  <section class=\"section section--indigo final-cta\">\n    <div class=\"container\">\n      <h2 class=\"t-display t-display--lg\">Own your member portal.</h2>\n      <p class=\"t-body--lg\">Open source. Flat pricing. AI-powered. Yours forever.</p>\n      <div class=\"final-cta__buttons\">\n        <a href=\"https://eagles.run402.com\" class=\"btn btn--white btn--lg\" target=\"_blank\">Explore Live Demo &rarr;</a>\n        <a href=\"https://github.com/kychee-com/wildlychee\" class=\"btn btn--outline btn--lg\" style=\"border-color:#fff;color:#fff\" target=\"_blank\">View on GitHub</a>\n      </div>\n    </div>\n  </section>\n\n  <!-- ======== FOOTER ======== -->\n  <footer class=\"footer\">\n    <div class=\"container\">\n      <p>\n        <strong>Wild Lychee</strong> is open source. Built on <a href=\"https://run402.com\" target=\"_blank\">Run402</a>.\n        &ensp;&middot;&ensp;\n        <a href=\"https://github.com/kychee-com/wildlychee\" target=\"_blank\">GitHub</a>\n        &ensp;&middot;&ensp;\n        <a href=\"https://eagles.run402.com\" target=\"_blank\">Eagles Demo</a>\n        &ensp;&middot;&ensp;\n        <a href=\"/compare.html\">Compare</a>\n      </p>\n    </div>\n  </footer>\n\n  <!-- Mobile nav toggle -->\n  <script>\n    document.getElementById('nav-toggle')?.addEventListener('click', () => {\n      document.getElementById('nav-links')?.classList.toggle('open');\n    });\n  </script>\n\n</body>\n</html>\n"
