/* ============================================
   Wild Lychee Marketing вҖ” Editorial Indie
   ============================================ */

@import url('https://fonts.googleapis.com/css2?family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;0,9..40,700;1,9..40,400&family=Instrument+Serif:ital@0;1&display=swap');

/* --- Tokens --- */
:root {
  --ink: #1a1625;
  --ink-muted: #6b6680;
  --ink-subtle: #9994a8;
  --cream: #faf7f2;
  --cream-dark: #f0ebe3;
  --indigo: #4338ca;
  --indigo-light: #6366f1;
  --indigo-dark: #3730a3;
  --indigo-wash: #eef2ff;
  --coral: #f97316;
  --coral-light: #fb923c;
  --rose: #f15b86;
  --rose-light: #f9a8c2;
  --rose-wash: #fff1f5;
  --green: #16a34a;
  --green-wash: #dcfce7;
  --red-wash: #fee2e2;
  --red-muted: #b91c1c;
  --font-display: 'Instrument Serif', Georgia, serif;
  --font-body: 'DM Sans', -apple-system, sans-serif;
  --max-w: 72rem;
  --ease: cubic-bezier(0.16, 1, 0.3, 1);
}

/* --- Reset --- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { scroll-behavior: smooth; }

body {
  font-family: var(--font-body);
  color: var(--ink);
  background: var(--cream);
  line-height: 1.65;
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden;
}

img { max-width: 100%; display: block; }
a { color: inherit; text-decoration: none; }

/* --- Layout --- */
.container {
  max-width: var(--max-w);
  margin: 0 auto;
  padding: 0 2rem;
}

.section {
  padding: 7rem 0;
  position: relative;
}

.section--cream { background: var(--cream); }
.section--white { background: #fff; }
.section--ink {
  background: var(--ink);
  color: #fff;
}
.section--indigo {
  background: var(--indigo);
  color: #fff;
}

/* Dot-grid texture overlay */
.section--dotted::before {
  content: '';
  position: absolute;
  inset: 0;
  background-image: radial-gradient(circle, var(--ink) 0.5px, transparent 0.5px);
  background-size: 24px 24px;
  opacity: 0.04;
  pointer-events: none;
}

/* Angled divider */
.slash {
  position: relative;
}
.slash::after {
  content: '';
  position: absolute;
  bottom: -2rem;
  left: 0;
  right: 0;
  height: 4rem;
  background: inherit;
  clip-path: polygon(0 0, 100% 0, 100% 30%, 0 100%);
  z-index: 2;
}

/* --- Typography --- */
.t-display {
  font-family: var(--font-display);
  font-weight: 400;
  line-height: 1.1;
  letter-spacing: -0.02em;
}

.t-display--xl { font-size: clamp(2.75rem, 6vw, 4.5rem); }
.t-display--lg { font-size: clamp(2rem, 4vw, 3rem); }
.t-display--md { font-size: clamp(1.5rem, 3vw, 2.25rem); }

.t-overline {
  font-family: var(--font-body);
  font-size: 0.8125rem;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--indigo);
}

.t-body { font-size: 1.125rem; color: var(--ink-muted); }
.t-body--lg { font-size: 1.25rem; color: var(--ink-muted); max-width: 38rem; }
.t-body--sm { font-size: 0.9375rem; color: var(--ink-muted); }

.t-italic { font-style: italic; }

/* --- Nav --- */
.nav {
  position: sticky;
  top: 0;
  z-index: 100;
  background: rgba(250, 247, 242, 0.9);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid rgba(26, 22, 37, 0.06);
  padding: 0.875rem 0;
}

.nav__inner {
  display: flex;
  align-items: center;
  gap: 2rem;
}

.nav__brand {
  font-family: var(--font-display);
  font-size: 1.375rem;
  color: var(--ink);
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex-shrink: 0;
}

.nav__brand-icon {
  width: 1.75rem;
  height: 1.75rem;
  background: var(--indigo);
  border-radius: 6px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  font-size: 1rem;
  transform: rotate(-6deg);
}

.nav__links {
  display: flex;
  align-items: center;
  gap: 0.25rem;
  margin-left: auto;
}

.nav__link {
  padding: 0.375rem 0.75rem;
  font-size: 0.875rem;
  font-weight: 500;
  color: var(--ink-muted);
  border-radius: 6px;
  transition: color 0.2s, background 0.2s;
}

.nav__link:hover {
  color: var(--ink);
  background: rgba(0,0,0,0.04);
}

.nav__cta {
  margin-left: 0.5rem;
}

.nav__toggle {
  display: none;
  background: none;
  border: none;
  font-size: 1.5rem;
  cursor: pointer;
  color: var(--ink);
  padding: 0.25rem;
  margin-left: auto;
}

/* --- Buttons --- */
.btn {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.75rem 1.5rem;
  border-radius: 8px;
  font-family: var(--font-body);
  font-size: 0.9375rem;
  font-weight: 600;
  border: none;
  cursor: pointer;
  transition: transform 0.15s var(--ease), box-shadow 0.2s, background 0.2s;
  text-decoration: none;
}
.btn:active { transform: scale(0.97); }

.btn--primary {
  background: var(--indigo);
  color: #fff;
  box-shadow: 0 1px 3px rgba(67, 56, 202, 0.3);
}
.btn--primary:hover {
  background: var(--indigo-dark);
  box-shadow: 0 4px 12px rgba(67, 56, 202, 0.3);
}

.btn--outline {
  background: transparent;
  color: var(--ink);
  border: 1.5px solid var(--ink);
}
.btn--outline:hover {
  background: var(--ink);
  color: var(--cream);
}

.btn--ghost {
  background: transparent;
  color: var(--indigo);
  padding: 0.75rem 1rem;
}
.btn--ghost:hover {
  background: var(--indigo-wash);
}

.btn--coral {
  background: var(--coral);
  color: #fff;
}
.btn--coral:hover {
  background: var(--coral-light);
}

.btn--white {
  background: #fff;
  color: var(--indigo);
}
.btn--white:hover {
  background: var(--cream);
}

.btn--lg {
  padding: 1rem 2rem;
  font-size: 1.0625rem;
  border-radius: 10px;
}

/* --- Hero --- */
.hero {
  padding: 8rem 0 6rem;
  position: relative;
}

.hero__content {
  max-width: 48rem;
}

.hero__headline {
  margin-bottom: 1.5rem;
}

.hero__headline em {
  color: var(--rose);
  font-style: normal;
  text-decoration: underline;
  text-decoration-color: var(--rose);
  text-underline-offset: 4px;
  text-decoration-thickness: 3px;
}

.hero__sub {
  margin-bottom: 2.5rem;
}

.hero__ctas {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
}

.hero__aside {
  position: absolute;
  right: 2rem;
  top: 50%;
  transform: translateY(-50%);
  width: 20rem;
  height: 20rem;
  background: var(--indigo-wash);
  border-radius: 50%;
  opacity: 0.5;
  filter: blur(60px);
  pointer-events: none;
}

/* --- Problem cards --- */
.problem-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;
  margin-bottom: 4rem;
}

.problem-card {
  background: #fff;
  border: 1px solid rgba(0,0,0,0.06);
  border-radius: 12px;
  padding: 2rem;
  position: relative;
  overflow: hidden;
}

.problem-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: var(--red-muted);
  opacity: 0.6;
}

.problem-card__name {
  font-weight: 700;
  font-size: 0.875rem;
  color: var(--red-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 0.75rem;
}

.problem-card__price {
  font-family: var(--font-display);
  font-size: 1.75rem;
  line-height: 1.2;
  margin-bottom: 0.5rem;
}

.problem-card__desc {
  font-size: 0.9375rem;
  color: var(--ink-muted);
  font-style: italic;
}

.problem-transition {
  text-align: center;
  max-width: 36rem;
  margin: 0 auto;
}

.problem-transition__what-if {
  font-family: var(--font-display);
  font-size: 2rem;
  font-style: italic;
  color: var(--indigo);
  margin-bottom: 1rem;
}

/* --- Feature grid --- */
.feature-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 1.25rem;
}

.feature-card {
  background: #fff;
  border: 1px solid rgba(0,0,0,0.06);
  border-radius: 12px;
  padding: 1.75rem;
  transition: transform 0.2s var(--ease), box-shadow 0.2s;
}

.feature-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(0,0,0,0.06);
}

.feature-card__icon {
  font-size: 1.75rem;
  margin-bottom: 0.75rem;
}

.feature-card__name {
  font-weight: 700;
  font-size: 1rem;
  margin-bottom: 0.375rem;
}

.feature-card__desc {
  font-size: 0.875rem;
  color: var(--ink-muted);
  line-height: 1.5;
}

/* --- AI section --- */
.ai-section {
  background: var(--ink);
  color: #fff;
  position: relative;
  overflow: hidden;
}

.ai-section .t-overline { color: var(--coral-light); }
.ai-section .t-body--lg { color: rgba(255,255,255,0.6); }

.ai-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.25rem;
  margin-bottom: 2rem;
}

.ai-card {
  background: rgba(255,255,255,0.06);
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: 12px;
  padding: 1.75rem;
  transition: background 0.2s;
}

.ai-card:hover {
  background: rgba(255,255,255,0.1);
}

.ai-card__icon {
  font-size: 1.5rem;
  margin-bottom: 0.75rem;
}

.ai-card__name {
  font-weight: 700;
  font-size: 1rem;
  margin-bottom: 0.375rem;
}

.ai-card__desc {
  font-size: 0.875rem;
  color: rgba(255,255,255,0.55);
  line-height: 1.5;
}

.ai-byok {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  background: rgba(255,255,255,0.06);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: 8px;
  padding: 0.75rem 1.25rem;
  font-size: 0.875rem;
  color: rgba(255,255,255,0.7);
}

/* Background glow */
.ai-section::before {
  content: '';
  position: absolute;
  top: -10rem;
  right: -10rem;
  width: 30rem;
  height: 30rem;
  background: radial-gradient(circle, var(--indigo) 0%, transparent 70%);
  opacity: 0.15;
  pointer-events: none;
}

/* --- Showcase gallery --- */
.showcase-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;
}

.showcase-card {
  border-radius: 12px;
  overflow: hidden;
  border: 1px solid rgba(0,0,0,0.08);
  background: #fff;
  transition: transform 0.2s var(--ease), box-shadow 0.2s;
}

.showcase-card:hover {
  transform: translateY(-3px);
  box-shadow: 0 12px 32px rgba(0,0,0,0.08);
}

.showcase-card__preview {
  height: 12rem;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-display);
  font-size: 1.25rem;
  color: #fff;
  position: relative;
}

.showcase-card__preview--eagles {
  background: linear-gradient(135deg, #1b365d 0%, #2d4a7a 100%);
}
.showcase-card__preview--yoga {
  background: linear-gradient(135deg, #7c3aed 0%, #a78bfa 100%);
}
.showcase-card__preview--bookclub {
  background: linear-gradient(135deg, #065f46 0%, #059669 100%);
}

.showcase-card__coming {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
  background: rgba(0,0,0,0.5);
  color: #fff;
  font-family: var(--font-body);
  font-size: 0.6875rem;
  font-weight: 600;
  padding: 0.25rem 0.625rem;
  border-radius: 99px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.showcase-card__body {
  padding: 1.25rem 1.5rem;
}

.showcase-card__name {
  font-weight: 700;
  font-size: 1.0625rem;
  margin-bottom: 0.25rem;
}

.showcase-card__niche {
  font-size: 0.8125rem;
  color: var(--ink-muted);
  margin-bottom: 0.75rem;
}

.showcase-card__link {
  font-size: 0.875rem;
  font-weight: 600;
  color: var(--indigo);
  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
}
.showcase-card__link:hover { text-decoration: underline; }

/* --- Pricing --- */
.pricing-comparison {
  overflow-x: auto;
  margin-bottom: 4rem;
  -webkit-overflow-scrolling: touch;
}

.pricing-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.9375rem;
  min-width: 32rem;
}

.pricing-table th {
  text-align: left;
  padding: 1rem 1.25rem;
  font-weight: 600;
  font-size: 0.8125rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--ink-muted);
  border-bottom: 2px solid var(--ink);
}

.pricing-table td {
  padding: 1rem 1.25rem;
  border-bottom: 1px solid rgba(0,0,0,0.06);
}

.pricing-table tr:last-child td { border-bottom: none; }

.pricing-table__highlight {
  color: var(--indigo);
  font-weight: 700;
}

.pricing-table__muted {
  color: var(--ink-subtle);
}

.plans-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;
}

.plan-card {
  background: #fff;
  border: 1px solid rgba(0,0,0,0.08);
  border-radius: 12px;
  padding: 2rem;
  display: flex;
  flex-direction: column;
}

.plan-card--featured {
  border-color: var(--indigo);
  box-shadow: 0 0 0 1px var(--indigo);
  position: relative;
}

.plan-card--featured::before {
  content: 'Most Popular';
  position: absolute;
  top: -0.75rem;
  left: 1.5rem;
  background: var(--indigo);
  color: #fff;
  font-size: 0.6875rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  padding: 0.25rem 0.75rem;
  border-radius: 99px;
}

.plan-card__name {
  font-family: var(--font-display);
  font-size: 1.5rem;
  margin-bottom: 0.25rem;
}

.plan-card__price {
  font-size: 2rem;
  font-weight: 800;
  color: var(--indigo);
  margin-bottom: 0.125rem;
}

.plan-card__price-sub {
  font-size: 0.8125rem;
  color: var(--ink-muted);
  margin-bottom: 1.25rem;
}

.plan-card__desc {
  font-size: 0.9375rem;
  color: var(--ink-muted);
  font-style: italic;
  margin-bottom: 1.5rem;
  flex: 1;
}

.plan-card__features {
  list-style: none;
  margin-bottom: 1.5rem;
}

.plan-card__features li {
  font-size: 0.875rem;
  padding: 0.375rem 0;
  border-bottom: 1px solid rgba(0,0,0,0.04);
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.plan-card__features li::before {
  content: '\2713';
  color: var(--green);
  font-weight: 700;
  font-size: 0.75rem;
}

/* --- Niche cards --- */
.niche-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 1rem;
}

.niche-card {
  background: #fff;
  border: 1px solid rgba(0,0,0,0.06);
  border-radius: 12px;
  padding: 1.5rem;
  text-align: center;
  transition: transform 0.2s var(--ease), box-shadow 0.2s;
}

.niche-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(0,0,0,0.06);
}

.niche-card--disabled {
  opacity: 0.5;
  pointer-events: none;
}

.niche-card__icon {
  font-size: 2rem;
  margin-bottom: 0.5rem;
}

.niche-card__name {
  font-weight: 700;
  font-size: 0.9375rem;
  margin-bottom: 0.25rem;
}

.niche-card__sub {
  font-size: 0.75rem;
  color: var(--ink-subtle);
}

/* --- Final CTA --- */
.final-cta {
  text-align: center;
}

.final-cta .t-display--lg {
  color: #fff;
  margin-bottom: 0.75rem;
}

.final-cta .t-body--lg {
  color: rgba(255,255,255,0.6);
  margin: 0 auto 2.5rem;
}

.final-cta__buttons {
  display: flex;
  justify-content: center;
  gap: 0.75rem;
  flex-wrap: wrap;
}

/* --- Footer --- */
.footer {
  padding: 2.5rem 0;
  border-top: 1px solid rgba(0,0,0,0.06);
  text-align: center;
  font-size: 0.8125rem;
  color: var(--ink-muted);
}

.footer a {
  color: var(--indigo);
  font-weight: 500;
}
.footer a:hover { text-decoration: underline; }

/* --- Section header utility --- */
.section-header {
  margin-bottom: 3rem;
}

.section-header--center {
  text-align: center;
  max-width: 40rem;
  margin-left: auto;
  margin-right: auto;
}

.section-header .t-overline { margin-bottom: 0.75rem; }
.section-header .t-display--lg { margin-bottom: 1rem; }

/* --- Spacing utils --- */
.mb-1 { margin-bottom: 0.5rem; }
.mb-2 { margin-bottom: 1rem; }
.mb-3 { margin-bottom: 1.5rem; }
.mb-4 { margin-bottom: 2rem; }
.mb-6 { margin-bottom: 3rem; }
.mt-2 { margin-top: 1rem; }
.mt-4 { margin-top: 2rem; }

/* --- Browser mockup --- */
.browser-mockup {
  max-width: 44rem;
  margin: 3rem auto 0;
  border-radius: 12px;
  overflow: hidden;
  box-shadow: 0 24px 64px rgba(26, 22, 37, 0.15), 0 0 0 1px rgba(0, 0, 0, 0.06);
  position: relative;
}

.browser-mockup__chrome {
  background: #f1f0f3;
  padding: 0.625rem 1rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.browser-mockup__dots {
  display: flex;
  gap: 0.375rem;
}

.browser-mockup__dots span {
  width: 0.5rem;
  height: 0.5rem;
  border-radius: 50%;
  background: #ccc;
}

.browser-mockup__url {
  flex: 1;
  background: #fff;
  border-radius: 4px;
  padding: 0.25rem 0.625rem;
  font-size: 0.6875rem;
  color: var(--ink-muted);
  font-family: var(--font-body);
}

.browser-mockup img {
  width: 100%;
  display: block;
}

.hero__stats {
  display: flex;
  justify-content: center;
  gap: 1rem;
  margin-top: 1.25rem;
}

.hero__stat {
  display: inline-flex;
  align-items: center;
  gap: 0.375rem;
  background: #fff;
  border: 1px solid rgba(0, 0, 0, 0.06);
  border-radius: 99px;
  padding: 0.375rem 0.875rem;
  font-size: 0.8125rem;
  font-weight: 600;
  color: var(--ink);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.04);
}

.hero__stat-dot {
  width: 0.5rem;
  height: 0.5rem;
  border-radius: 50%;
  background: var(--green);
}

/* --- Product tour tiles --- */
.tour-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 1.25rem;
}

.tour-tile {
  border-radius: 12px;
  overflow: hidden;
  border: 1px solid rgba(0, 0, 0, 0.08);
  background: #fff;
  transition: transform 0.2s var(--ease), box-shadow 0.2s;
  display: block;
  color: inherit;
}

.tour-tile:hover {
  transform: translateY(-3px);
  box-shadow: 0 12px 32px rgba(0, 0, 0, 0.08);
}

.tour-tile__img {
  height: 11rem;
  overflow: hidden;
}

.tour-tile__img img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: top;
}

.tour-tile__body {
  padding: 1rem 1.25rem;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.tour-tile__name {
  font-weight: 700;
  font-size: 0.9375rem;
}

.tour-tile__link {
  font-size: 0.8125rem;
  font-weight: 600;
  color: var(--indigo);
}

/* --- Benefits cards --- */
.benefits-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;
}

.benefit-card {
  background: #fff;
  border: 1px solid rgba(0, 0, 0, 0.06);
  border-radius: 12px;
  padding: 2rem;
}

.benefit-card__icon {
  font-size: 2rem;
  margin-bottom: 0.75rem;
}

.benefit-card__title {
  font-weight: 700;
  font-size: 1.125rem;
  margin-bottom: 0.5rem;
}

.benefit-card__desc {
  font-size: 0.9375rem;
  color: var(--ink-muted);
  line-height: 1.5;
}

/* --- How it works --- */
.steps-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 2rem;
  counter-reset: step;
}

.step-card {
  text-align: center;
  counter-increment: step;
}

.step-card__number {
  width: 3rem;
  height: 3rem;
  border-radius: 50%;
  background: var(--indigo);
  color: #fff;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 1.25rem;
  font-weight: 700;
  margin-bottom: 1rem;
}

.step-card__title {
  font-weight: 700;
  font-size: 1.0625rem;
  margin-bottom: 0.5rem;
}

.step-card__desc {
  font-size: 0.9375rem;
  color: var(--ink-muted);
  line-height: 1.5;
}

/* --- FAQ --- */
.faq-list {
  max-width: 44rem;
  margin: 0 auto;
}

.faq-item {
  border-bottom: 1px solid rgba(0, 0, 0, 0.06);
}

.faq-item:last-child {
  border-bottom: none;
}

.faq-item summary {
  padding: 1.25rem 0;
  font-weight: 600;
  font-size: 1.0625rem;
  cursor: pointer;
  list-style: none;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.faq-item summary::after {
  content: '+';
  font-size: 1.25rem;
  color: var(--ink-muted);
  transition: transform 0.2s;
}

.faq-item[open] summary::after {
  transform: rotate(45deg);
}

.faq-item p {
  padding: 0 0 1.25rem;
  color: var(--ink-muted);
  font-size: 0.9375rem;
  line-height: 1.65;
}

/* --- Compare link --- */
.compare-link {
  text-align: center;
  margin-top: 2rem;
  font-size: 0.9375rem;
  color: var(--ink-muted);
}

.compare-link a {
  color: var(--indigo);
  font-weight: 600;
}

.compare-link a:hover {
  text-decoration: underline;
}

/* ============================================
   Responsive
   ============================================ */

@media (max-width: 1024px) {
  .feature-grid { grid-template-columns: repeat(2, 1fr); }
  .ai-grid { grid-template-columns: repeat(2, 1fr); }
  .niche-grid { grid-template-columns: repeat(2, 1fr); }
  .plans-grid { grid-template-columns: 1fr; max-width: 28rem; }
  .benefits-grid { grid-template-columns: 1fr; max-width: 28rem; }
  .steps-grid { grid-template-columns: 1fr; max-width: 28rem; }
}

@media (max-width: 768px) {
  .section { padding: 4rem 0; }
  .container { padding: 0 1.25rem; }

  /* Nav mobile */
  .nav__links { display: none; }
  .nav__links.open {
    display: flex;
    flex-direction: column;
    position: absolute;
    top: 100%;
    left: 0;
    right: 0;
    background: var(--cream);
    border-bottom: 1px solid rgba(0,0,0,0.06);
    padding: 1rem 1.25rem;
    gap: 0.125rem;
  }
  .nav__links.open .nav__cta { margin-left: 0; margin-top: 0.5rem; }
  .nav__toggle { display: block; }

  /* Hero */
  .hero { padding: 5rem 0 4rem; }
  .hero__aside { display: none; }
  .hero__ctas { flex-direction: column; }
  .hero__ctas .btn { justify-content: center; }

  /* Grids */
  .problem-grid { grid-template-columns: 1fr; }
  .feature-grid { grid-template-columns: 1fr; }
  .ai-grid { grid-template-columns: 1fr; }
  .showcase-grid { grid-template-columns: 1fr; }
  .tour-grid { grid-template-columns: 1fr; }
  .benefits-grid { grid-template-columns: 1fr; }
  .steps-grid { grid-template-columns: 1fr; }
  .plans-grid { grid-template-columns: 1fr; }
  .niche-grid { grid-template-columns: repeat(2, 1fr); }

  .pricing-table { font-size: 0.8125rem; }
  .pricing-table th, .pricing-table td { padding: 0.75rem; }
}

@media (max-width: 480px) {
  .niche-grid { grid-template-columns: 1fr; }
}
